{
  "name": "ImmoManager Pro",
  "description": "Eine umfassende Immobilienverwaltungslösung für private Vermieter mit KI-gestützter Erstellung von Exposés, Mieteranschreiben und Betriebskostenabrechnungen.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum HouseType {
  DETACHED = 'Einfamilienhaus',
  SEMI_DETACHED = 'Doppelhaushälfte',
  APARTMENT_BLOCK = 'Mehrfamilienhaus',
  CONDO = 'Eigentumswohnung'
}

export interface Unit {
  id: string;
  number: string;
  size: number; // m²
  baseRent: number;
  utilityPrepayment: number;
  tenantId?: string;
}

export interface Property {
  id: string;
  name: string;
  type: HouseType;
  address: string;
  units: Unit[];
}

export interface Tenant {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  startDate: string;
}

export enum TransactionType {
  INCOME = 'Einnahme',
  EXPENSE = 'Ausgabe'
}

export interface Transaction {
  id: string;
  propertyId: string;
  unitId?: string;
  type: TransactionType;
  category: string;
  amount: number;
  date: string;
  description: string;
}

export interface Handyman {
  id: string;
  name: string;
  trade: string;
  phone: string;
  email: string;
  address?: string;
}

export type View = 'dashboard' | 'properties' | 'tenants' | 'finances' | 'handymen' | 'tools';

import { GoogleGenAI } from "@google/genai";
import { Property, Tenant } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateTenantLetter = async (
  tenant: Tenant,
  property: Property,
  subject: string,
  context: string
): Promise<string> => {
  const prompt = `Erstelle einen formellen Brief an einen Mieter auf Deutsch.
  Absender: Vermieter
  Empfänger: ${tenant.firstName} ${tenant.lastName}, wohnhaft in ${property.address}
  Betreff: ${subject}
  Zusatzinfo: ${context}
  Der Ton soll professionell, höflich aber bestimmt sein. Verwende das aktuelle Datum.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, der Brief konnte nicht generiert werden.";
  }
};

export const generateExpose = async (property: Property): Promise<string> => {
  const prompt = `Erstelle ein attraktives Immobilien-Exposé für folgendes Objekt:
  Objekt: ${property.name}
  Typ: ${property.type}
  Adresse: ${property.address}
  Einheiten: ${property.units.length}
  Gesamtfläche: ${property.units.reduce((sum, u) => sum + u.size, 0)} m²
  Strukturieren das Exposé in: Einleitung, Objektbeschreibung, Lage und Highlights.
  Der Text soll werblich und ansprechend für potenzielle Käufer oder Mieter sein.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, das Exposé konnte nicht generiert werden.";
  }
};

import React, { useState, useEffect } from 'react';
import { View, Property, Tenant, Transaction, Handyman, HouseType, TransactionType } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import PropertiesList from './components/PropertiesList';
import TenantManager from './components/TenantManager';
import FinanceTracker from './components/FinanceTracker';
import HandymanContacts from './components/HandymanContacts';
import AITools from './components/AITools';

const initialProperties: Property[] = [
  {
    id: 'p1',
    name: 'Sonnenresidenz',
    type: HouseType.APARTMENT_BLOCK,
    address: 'Sonnenallee 15, 12047 Berlin',
    units: [
      { id: 'u1', number: 'EG links', size: 65, baseRent: 850, utilityPrepayment: 150, tenantId: 't1' },
      { id: 'u2', number: '1. OG rechts', size: 45, baseRent: 600, utilityPrepayment: 110 }
    ]
  }
];

const initialTenants: Tenant[] = [
  { id: 't1', firstName: 'Max', lastName: 'Mustermann', email: 'max@example.com', phone: '0170-1234567', startDate: '2022-01-01' }
];

const initialHandymen: Handyman[] = [
  { id: 'h1', name: 'Sanitär Schmidt', trade: 'Klempner', phone: '030-987654', email: 'info@schmidt-sanitaer.de' }
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [properties, setProperties] = useState<Property[]>(initialProperties);
  const [tenants, setTenants] = useState<Tenant[]>(initialTenants);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [handymen, setHandymen] = useState<Handyman[]>(initialHandymen);

  const addTransaction = (t: Transaction) => setTransactions(prev => [...prev, t]);

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar currentView={currentView} setView={setCurrentView} />

      <main className="flex-1 ml-64 p-8">
        <header className="mb-8 flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-slate-800">
              {currentView === 'dashboard' && 'Übersicht'}
              {currentView === 'properties' && 'Immobilien'}
              {currentView === 'tenants' && 'Mieterverwaltung'}
              {currentView === 'finances' && 'Finanzen'}
              {currentView === 'handymen' && 'Handwerker'}
              {currentView === 'tools' && 'KI-Werkzeuge'}
            </h1>
            <p className="text-slate-500 mt-1">Willkommen zurück, Ihr Portfolio auf einen Blick.</p>
          </div>
          <div className="flex items-center space-x-4">
            <button className="bg-white p-2 rounded-full shadow-sm hover:shadow-md transition">
              <i className="fa-solid fa-bell text-slate-500"></i>
            </button>
            <div className="h-10 w-10 bg-indigo-600 rounded-full flex items-center justify-center text-white font-bold">
              VM
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {currentView === 'dashboard' && (
            <Dashboard 
              properties={properties} 
              tenants={tenants} 
              transactions={transactions} 
            />
          )}
          {currentView === 'properties' && (
            <PropertiesList properties={properties} setProperties={setProperties} />
          )}
          {currentView === 'tenants' && (
            <TenantManager tenants={tenants} setTenants={setTenants} properties={properties} />
          )}
          {currentView === 'finances' && (
            <FinanceTracker 
              transactions={transactions} 
              addTransaction={addTransaction} 
              properties={properties} 
            />
          )}
          {currentView === 'handymen' && (
            <HandymanContacts handymen={handymen} setHandymen={setHandymen} />
          )}
          {currentView === 'tools' && (
            <AITools properties={properties} tenants={tenants} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
