export default Sidebar;

import React from 'react';
import { Property, Tenant, Transaction, TransactionType } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DashboardProps {
  properties: Property[];
  tenants: Tenant[];
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ properties, tenants, transactions }) => {
  const totalUnits = properties.reduce((sum, p) => sum + p.units.length, 0);
  const occupiedUnits = properties.reduce((sum, p) => sum + p.units.filter(u => u.tenantId).length, 0);
  const occupancyRate = totalUnits > 0 ? (occupiedUnits / totalUnits) * 100 : 0;

  const income = transactions
    .filter(t => t.type === TransactionType.INCOME)
    .reduce((sum, t) => sum + t.amount, 0);

  const expenses = transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .reduce((sum, t) => sum + t.amount, 0);

  const chartData = [
    { name: 'Einnahmen', value: income, color: '#10b981' },
    { name: 'Ausgaben', value: expenses, color: '#ef4444' },
    { name: 'Cashflow', value: income - expenses, color: '#6366f1' }
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Objekte" 
          value={properties.length.toString()} 
          icon="fa-building" 
          color="text-blue-600" 
          bgColor="bg-blue-100" 
        />
        <StatCard 
          title="Mieter" 
          value={tenants.length.toString()} 
          icon="fa-users" 
          color="text-purple-600" 
          bgColor="bg-purple-100" 
        />
        <StatCard 
          title="Belegung" 
          value={`${occupancyRate.toFixed(0)}%`} 
          icon="fa-door-open" 
          color="text-emerald-600" 
          bgColor="bg-emerald-100" 
        />
        <StatCard 
          title="Cashflow" 
          value={`${(income - expenses).toFixed(2)} €`} 
          icon="fa-euro-sign" 
          color="text-indigo-600" 
          bgColor="bg-indigo-100" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Finanzübersicht</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Letzte Aktivitäten</h3>
          <div className="space-y-4">
            {transactions.length > 0 ? (
              transactions.slice(-5).reverse().map(t => (
                <div key={t.id} className="flex items-center space-x-3 p-3 hover:bg-slate-50 rounded-lg transition">
                  <div className={`p-2 rounded-full ${t.type === TransactionType.INCOME ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                    <i className={`fa-solid ${t.type === TransactionType.INCOME ? 'fa-arrow-up' : 'fa-arrow-down'} text-xs`}></i>
                  </div>
                  <div className="flex-1">
                    <p className="text-sm font-semibold">{t.description}</p>
                    <p className="text-xs text-slate-500">{t.date}</p>
                  </div>
                  <span className={`text-sm font-bold ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-red-600'}`}>
                    {t.type === TransactionType.INCOME ? '+' : '-'}{t.amount}€
                  </span>
                </div>
              ))
            ) : (
              <p className="text-slate-400 text-sm text-center py-8">Keine Transaktionen erfasst.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

interface StatCardProps {
  title: string;
  value: string;
  icon: string;
  color: string;
  bgColor: string;
}

const StatCard: React.FC<StatCardProps> = ({ title, value, icon, color, bgColor }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
    <div className="flex justify-between items-start">
      <div>
        <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
      </div>
      <div className={`${bgColor} ${color} p-3 rounded-xl`}>
        <i className={`fa-solid ${icon} text-lg`}></i>
      </div>
    </div>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { Property, HouseType } from '../types';

interface PropertiesListProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
}

const PropertiesList: React.FC<PropertiesListProps> = ({ properties, setProperties }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [newProp, setNewProp] = useState({ name: '', address: '', type: HouseType.APARTMENT_BLOCK });

  const addProperty = () => {
    if (!newProp.name || !newProp.address) return;
    const p: Property = {
      id: Math.random().toString(36).substr(2, 9),
      ...newProp,
      units: []
    };
    setProperties([...properties, p]);
    setShowAdd(false);
    setNewProp({ name: '', address: '', type: HouseType.APARTMENT_BLOCK });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Ihre Immobilien ({properties.length})</h2>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 flex items-center transition"
        >
          <i className="fa-solid fa-plus mr-2"></i> Neues Objekt
        </button>
      </div>

      {showAdd && (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold text-lg mb-4">Immobilie hinzufügen</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              className="border p-2 rounded-lg" 
              placeholder="Name des Objekts"
              value={newProp.name}
              onChange={e => setNewProp({...newProp, name: e.target.value})}
            />
            <input 
              className="border p-2 rounded-lg" 
              placeholder="Adresse"
              value={newProp.address}
              onChange={e => setNewProp({...newProp, address: e.target.value})}
            />
            <select 
              className="border p-2 rounded-lg"
              value={newProp.type}
              onChange={e => setNewProp({...newProp, type: e.target.value as HouseType})}
            >
              {Object.values(HouseType).map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>
          <div className="mt-4 flex space-x-3">
            <button onClick={addProperty} className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium">Speichern</button>
            <button onClick={() => setShowAdd(false)} className="text-slate-500 hover:text-slate-700">Abbrechen</button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {properties.map(p => (
          <div key={p.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition group">
            <div className="h-48 bg-slate-200 relative">
              <img src={`https://picsum.photos/seed/${p.id}/600/400`} alt={p.name} className="w-full h-full object-cover opacity-90" />
              <div className="absolute top-4 right-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-xs font-bold text-indigo-600 uppercase">
                {p.type}
              </div>
            </div>
            <div className="p-6">
              <h3 className="text-xl font-bold text-slate-800 mb-1">{p.name}</h3>
              <p className="text-slate-500 flex items-center text-sm mb-4">
                <i className="fa-solid fa-location-dot mr-2 text-slate-400"></i> {p.address}
              </p>

              <div className="grid grid-cols-2 gap-4 border-t border-slate-100 pt-4">
                <div className="text-center p-2 bg-slate-50 rounded-lg">
                  <p className="text-xs text-slate-500 font-medium">Einheiten</p>
                  <p className="text-lg font-bold text-slate-800">{p.units.length}</p>
                </div>
                <div className="text-center p-2 bg-slate-50 rounded-lg">
                  <p className="text-xs text-slate-500 font-medium">Gesamtfläche</p>
                  <p className="text-lg font-bold text-slate-800">{p.units.reduce((s, u) => s + u.size, 0)} m²</p>
                </div>
              </div>

              <button className="w-full mt-6 py-2 rounded-xl border border-slate-200 text-slate-600 font-semibold hover:bg-slate-50 transition">
                Details ansehen
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PropertiesList;

import React, { useState } from 'react';
import { Transaction, TransactionType, Property } from '../types';

interface FinanceTrackerProps {
  transactions: Transaction[];
  addTransaction: (t: Transaction) => void;
  properties: Property[];
}

const FinanceTracker: React.FC<FinanceTrackerProps> = ({ transactions, addTransaction, properties }) => {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Partial<Transaction>>({
    type: TransactionType.INCOME,
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    description: '',
    category: 'Miete'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.propertyId || !form.amount || !form.description) return;

    addTransaction({
      id: Math.random().toString(36).substr(2, 9),
      ...form as Transaction
    });
    setShowForm(false);
    setForm({
      type: TransactionType.INCOME,
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      description: '',
      category: 'Miete'
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Transaktionen</h2>
        <button 
          onClick={() => setShowForm(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
        >
          Buchung erfassen
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 animate-in slide-in-from-top-2 duration-300">
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Typ</label>
              <select 
                className="w-full border p-2 rounded-lg"
                value={form.type}
                onChange={e => setForm({...form, type: e.target.value as TransactionType})}
              >
                <option value={TransactionType.INCOME}>Einnahme</option>
                <option value={TransactionType.EXPENSE}>Ausgabe</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Immobilie</label>
              <select 
                className="w-full border p-2 rounded-lg"
                value={form.propertyId}
                onChange={e => setForm({...form, propertyId: e.target.value})}
                required
              >
                <option value="">Wählen...</option>
                {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Betrag (€)</label>
              <input 
                type="number"
                className="w-full border p-2 rounded-lg"
                value={form.amount}
                onChange={e => setForm({...form, amount: parseFloat(e.target.value)})}
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Kategorie</label>
              <input 
                className="w-full border p-2 rounded-lg"
                placeholder="z.B. Instandhaltung, Miete"
                value={form.category}
                onChange={e => setForm({...form, category: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Datum</label>
              <input 
                type="date"
                className="w-full border p-2 rounded-lg"
                value={form.date}
                onChange={e => setForm({...form, date: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Beschreibung</label>
              <input 
                className="w-full border p-2 rounded-lg"
                placeholder="Was wurde gebucht?"
                value={form.description}
                onChange={e => setForm({...form, description: e.target.value})}
                required
              />
            </div>
            <div className="md:col-span-full flex space-x-3 mt-4">
              <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold">Buchen</button>
              <button type="button" onClick={() => setShowForm(false)} className="text-slate-500">Abbrechen</button>
            </div>
          </form>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 text-xs font-bold uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Datum</th>
              <th className="px-6 py-4">Objekt</th>
              <th className="px-6 py-4">Kategorie / Beschreibung</th>
              <th className="px-6 py-4 text-right">Betrag</th>
            </tr>
          </thead>
