        <p className="text-[10px] md:text-sm font-bold text-slate-400 uppercase tracking-wider mb-0.5 md:mb-1">{title}</p>
        <h3 className="text-lg md:text-2xl font-black text-slate-800">{value}</h3>
      </div>
    </div>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, TransactionType, Property } from '../types';

interface FinanceTrackerProps {
  transactions: Transaction[];
  addTransaction: (t: Transaction) => void;
  properties: Property[];
}

const FinanceTracker: React.FC<FinanceTrackerProps> = ({ transactions, addTransaction, properties }) => {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState<Partial<Transaction>>({
    type: TransactionType.INCOME,
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    description: '',
    category: 'Miete'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.propertyId || !form.amount || !form.description) return;

    addTransaction({
      id: Math.random().toString(36).substr(2, 9),
      ...form as Transaction
    });
    setShowForm(false);
    setForm({
      type: TransactionType.INCOME,
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      description: '',
      category: 'Miete'
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Transaktionen</h2>
        <button 
          onClick={() => setShowForm(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 text-sm md:text-base"
        >
          <i className="fa-solid fa-plus mr-2"></i> Buchung
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-2xl shadow-xl border border-indigo-100 animate-in slide-in-from-top-2 duration-300">
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Typ</label>
              <div className="flex bg-slate-100 p-1 rounded-xl">
                <button 
                  type="button" 
                  onClick={() => setForm({...form, type: TransactionType.INCOME})}
                  className={`flex-1 py-2 rounded-lg text-xs font-bold transition ${form.type === TransactionType.INCOME ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500'}`}
                >
                  Einnahme
                </button>
                <button 
                  type="button" 
                  onClick={() => setForm({...form, type: TransactionType.EXPENSE})}
                  className={`flex-1 py-2 rounded-lg text-xs font-bold transition ${form.type === TransactionType.EXPENSE ? 'bg-white text-red-600 shadow-sm' : 'text-slate-500'}`}
                >
                  Ausgabe
                </button>
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Immobilie</label>
              <select 
                className="w-full border border-slate-200 p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500"
