                onChange={e => setForm({...form, propertyId: e.target.value})}
                required
              >
                <option value="">Wählen...</option>
                {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Betrag (€)</label>
              <input 
                type="number"
                className="w-full border border-slate-200 p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"
                value={form.amount}
                onChange={e => setForm({...form, amount: parseFloat(e.target.value)})}
                required
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Kategorie</label>
              <input 
                className="w-full border border-slate-200 p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500"
                placeholder="z.B. Instandhaltung, Miete"
                value={form.category}
                onChange={e => setForm({...form, category: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Datum</label>
              <input 
                type="date"
                className="w-full border border-slate-200 p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500"
