            <input className="border border-slate-200 p-2.5 rounded-xl outline-none" placeholder="Nachname" value={newTenant.lastName} onChange={e => setNewTenant({...newTenant, lastName: e.target.value})} />
            <input className="border border-slate-200 p-2.5 rounded-xl outline-none" placeholder="E-Mail" value={newTenant.email} onChange={e => setNewTenant({...newTenant, email: e.target.value})} />
            <input className="border border-slate-200 p-2.5 rounded-xl outline-none" placeholder="Telefon" value={newTenant.phone} onChange={e => setNewTenant({...newTenant, phone: e.target.value})} />
