import React, { useState, useRef } from 'react';
import { Property, HouseType, PropertyDocument } from '../types';

interface PropertiesListProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  onGenerateExpose?: (propertyId: string) => void;
}

const PropertiesList: React.FC<PropertiesListProps> = ({ properties, setProperties, onGenerateExpose }) => {
  const [showAdd, setShowAdd] = useState(false);
  const [selectedPropId, setSelectedPropId] = useState<string | null>(null);
  const [newProp, setNewProp] = useState({ name: '', address: '', type: HouseType.APARTMENT_BLOCK });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addProperty = () => {
    if (!newProp.name || !newProp.address) return;
    const p: Property = {
      id: Math.random().toString(36).substr(2, 9),
      ...newProp,
      units: [],
      documents: []
    };
    setProperties([...properties, p]);
    setShowAdd(false);
    setNewProp({ name: '', address: '', type: HouseType.APARTMENT_BLOCK });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>, propertyId: string) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const base64Data = e.target?.result as string;
      const newDoc: PropertyDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        category: 'Dokument', // Default category
        uploadDate: new Date().toLocaleDateString('de-DE'),
        fileSize: (file.size / 1024 / 1024).toFixed(2) + ' MB',
        fileData: base64Data,
        mimeType: file.type
      };

      setProperties(prev => prev.map(p => 
        p.id === propertyId 
          ? { ...p, documents: [...(p.documents || []), newDoc] } 
          : p
      ));
    };
    reader.readAsDataURL(file);
  };

  const downloadDocument = (doc: PropertyDocument) => {
    const link = document.createElement('a');
    link.href = doc.fileData;
    link.download = doc.name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const deleteDocument = (propertyId: string, docId: string) => {
    setProperties(prev => prev.map(p => 
      p.id === propertyId 
        ? { ...p, documents: (p.documents || []).filter(d => d.id !== docId) } 
        : p
    ));
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-slate-800">Ihre Immobilien ({properties.length})</h2>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 flex items-center transition"
        >
          <i className="fa-solid fa-plus mr-2"></i> Neues Objekt
        </button>
      </div>

      {showAdd && (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold text-lg mb-4 text-slate-800">Immobilie hinzufügen</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              className="border border-slate-200 p-2.5 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
              placeholder="Name des Objekts"
              value={newProp.name}
              onChange={e => setNewProp({...newProp, name: e.target.value})}
            />
            <input 
              className="border border-slate-200 p-2.5 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
              placeholder="Adresse"
              value={newProp.address}
              onChange={e => setNewProp({...newProp, address: e.target.value})}
            />
            <select 
              className="border border-slate-200 p-2.5 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              value={newProp.type}
              onChange={e => setNewProp({...newProp, type: e.target.value as HouseType})}
            >
              {Object.values(HouseType).map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>
          <div className="mt-4 flex space-x-3">
            <button onClick={addProperty} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-medium shadow-lg shadow-indigo-200">Speichern</button>
            <button onClick={() => setShowAdd(false)} className="text-slate-500 hover:text-slate-700 px-4 py-2">Abbrechen</button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 gap-6">
        {properties.map(p => (
          <div key={p.id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition">
            <div className="flex flex-col md:flex-row">
              <div className="md:w-1/3 h-48 md:h-auto bg-slate-200 relative">
                <img src={`https://picsum.photos/seed/${p.id}/600/400`} alt={p.name} className="w-full h-full object-cover opacity-90" />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-xs font-bold text-indigo-600 uppercase">
                  {p.type}
                </div>
              </div>
              <div className="p-6 flex-1">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-2xl font-bold text-slate-800 mb-1">{p.name}</h3>
                    <p className="text-slate-500 flex items-center text-sm mb-4">
                      <i className="fa-solid fa-location-dot mr-2 text-slate-400"></i> {p.address}
                    </p>
                  </div>
                  <div className="flex space-x-2">
                    <button 
                      onClick={() => onGenerateExpose && onGenerateExpose(p.id)}
                      className="px-4 py-2 rounded-xl text-sm font-bold bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition flex items-center border border-emerald-100"
                    >
                      <i className="fa-solid fa-file-pdf mr-2"></i> Exposé
                    </button>
                    <button 
                      onClick={() => setSelectedPropId(selectedPropId === p.id ? null : p.id)}
                      className={`px-4 py-2 rounded-xl text-sm font-bold transition flex items-center ${selectedPropId === p.id ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
                    >
                      <i className="fa-solid fa-file-shield mr-2"></i> Dokumente
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-4 border-t border-slate-100 pt-4 mb-4">
                  <div className="text-center p-2 bg-slate-50 rounded-xl">
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Einheiten</p>
                    <p className="text-lg font-bold text-slate-800">{p.units.length}</p>
                  </div>
                  <div className="text-center p-2 bg-slate-50 rounded-xl">
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Gesamtfläche</p>
                    <p className="text-lg font-bold text-slate-800">{p.units.reduce((s, u) => s + u.size, 0)} m²</p>
                  </div>
                  <div className="text-center p-2 bg-slate-50 rounded-xl">
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Dokumente</p>
                    <p className="text-lg font-bold text-slate-800">{p.documents?.length || 0}</p>
                  </div>
                </div>

                {selectedPropId === p.id && (
                  <div className="mt-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 animate-in slide-in-from-top-2 duration-300">
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="font-bold text-slate-800 text-sm">Dokumentenarchiv</h4>
                      <label className="cursor-pointer bg-white border border-indigo-200 text-indigo-600 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-indigo-50 transition">
                        <i className="fa-solid fa-upload mr-2"></i> Datei hochladen
                        <input 
                          type="file" 
                          className="hidden" 
                          onChange={(e) => handleFileUpload(e, p.id)}
                          accept=".pdf,.doc,.docx,.jpg,.png"
                        />
                      </label>
                    </div>

                    <div className="space-y-2">
                      {p.documents && p.documents.length > 0 ? (
                        p.documents.map(doc => (
                          <div key={doc.id} className="flex items-center justify-between p-3 bg-white rounded-xl border border-slate-100 shadow-sm hover:border-indigo-200 transition">
                            <div className="flex items-center space-x-3">
                              <div className="bg-indigo-50 p-2 rounded-lg text-indigo-500">
                                {doc.mimeType.includes('pdf') ? (
                                  <i className="fa-solid fa-file-pdf text-lg"></i>
                                ) : (
                                  <i className="fa-solid fa-file-image text-lg"></i>
                                )}
                              </div>
                              <div>
                                <p className="text-sm font-bold text-slate-800 max-w-[200px] truncate">{doc.name}</p>
                                <p className="text-[10px] text-slate-400 font-medium">{doc.uploadDate} • {doc.fileSize}</p>
                              </div>
                            </div>
                            <div className="flex space-x-2">
                              <button 
                                onClick={() => downloadDocument(doc)}
                                className="p-2 text-slate-400 hover:text-indigo-600 transition"
                                title="Herunterladen"
                              >
                                <i className="fa-solid fa-download"></i>
                              </button>
                              <button 
                                onClick={() => deleteDocument(p.id, doc.id)}
                                className="p-2 text-slate-400 hover:text-red-500 transition"
                                title="Löschen"
                              >
                                <i className="fa-solid fa-trash-can"></i>
                              </button>
                            </div>
                          </div>
                        ))
                      ) : (
                        <div className="text-center py-6 text-slate-400">
                          <i className="fa-solid fa-folder-open text-2xl mb-2 opacity-30"></i>
                          <p className="text-xs">Noch keine Dokumente hinterlegt.</p>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PropertiesList;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Tenant, Transaction, TransactionType } from '../types';
import { generateTenantLetter, generateExpose, generateUtilityStatementLetter } from '../services/geminiService';

interface AIToolsProps {
  properties: Property[];
  tenants: Tenant[];
  transactions: Transaction[];
  initialPropertyId?: string;
}

const AITools: React.FC<AIToolsProps> = ({ properties, tenants, transactions, initialPropertyId }) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');
  const [activeTab, setActiveTab] = useState<'letter' | 'expose' | 'utility'>('letter');

  const [letterConfig, setLetterConfig] = useState({
    tenantId: '',
    propertyId: '',
    subject: 'Mieterhöhung gemäß Mietspiegel',
    context: 'Die letzte Erhöhung war vor 3 Jahren. Wir müssen an den aktuellen Marktwert anpassen.'
  });

  const [utilityConfig, setUtilityConfig] = useState({
    propertyId: '',
    year: '2023'
  });

  const [exposeConfig, setExposeConfig] = useState({
    propertyId: '',
    purpose: 'Vermietung' as 'Vermietung' | 'Verkauf',
    targetGroup: 'Junge Familien',
    tone: 'Modern & Begeisternd'
  });

  // Handle deep-linking / pre-selection
  useEffect(() => {
    if (initialPropertyId) {
      setActiveTab('expose');
      setExposeConfig(prev => ({ ...prev, propertyId: initialPropertyId }));
    }
  }, [initialPropertyId]);

  // Calculation Logic for Utility Statement
  const utilityReport = useMemo(() => {
    if (!utilityConfig.propertyId) return null;

    const property = properties.find(p => p.id === utilityConfig.propertyId);
    if (!property) return null;

    const propertyExpenses = transactions.filter(t => 
      t.propertyId === utilityConfig.propertyId && 
      t.type === TransactionType.EXPENSE &&
      t.date.startsWith(utilityConfig.year)
    );

    const totalExpenses = propertyExpenses.reduce((sum, t) => sum + t.amount, 0);
    const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
    const costPerM2 = totalArea > 0 ? totalExpenses / totalArea : 0;

    const unitDetails = property.units.map(u => {
      const tenant = tenants.find(t => t.id === u.tenantId);
      const share = u.size * costPerM2;
      const prepaid = u.utilityPrepayment * 12; // Assuming full year
      const balance = share - prepaid;

      return {
        unit: u,
        tenant,
        share,
        prepaid,
        balance
      };
    });

    return {
      property,
      totalExpenses,
      totalArea,
      costPerM2,
      unitDetails
    };
  }, [utilityConfig, properties, transactions, tenants]);

  const handleGenerateLetter = async () => {
    const tenant = tenants.find(t => t.id === letterConfig.tenantId);
    const property = properties.find(p => p.id === letterConfig.propertyId);
    if (!tenant || !property) return alert('Bitte Mieter und Objekt wählen.');

    setLoading(true);
    const text = await generateTenantLetter(tenant, property, letterConfig.subject, letterConfig.context);
    setResult(text);
    setLoading(false);
  };

  const handleGenerateExposeClick = async () => {
    const property = properties.find(p => p.id === exposeConfig.propertyId);
    if (!property) return alert('Bitte ein Objekt wählen.');

    setLoading(true);
    const text = await generateExpose(
      property, 
      exposeConfig.purpose, 
      exposeConfig.targetGroup, 
      exposeConfig.tone
    );
    setResult(text);
    setLoading(false);
  };

  const handleGenerateUtilityLetter = async (detail: any) => {
    if (!detail.tenant || !utilityReport) return;
    setLoading(true);
    const text = await generateUtilityStatementLetter(
      detail.tenant,
      utilityReport.property,
      utilityConfig.year,
      utilityReport.totalExpenses,
      detail.share,
      detail.prepaid,
      detail.balance
    );
    setResult(text);
    setLoading(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-xl shadow-sm border border-slate-100 mb-2 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('letter')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'letter' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Anschreiben
          </button>
          <button 
            onClick={() => setActiveTab('expose')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'expose' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Exposé
          </button>
          <button 
            onClick={() => setActiveTab('utility')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'utility' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Abrechnung
          </button>
        </div>

        {activeTab === 'letter' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-indigo-100 text-indigo-600 p-2 rounded-lg">
                <i className="fa-solid fa-envelope-open-text text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Briefvorlage generieren</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Mieter</label>
                <select 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.tenantId}
                  onChange={e => setLetterConfig({...letterConfig, tenantId: e.target.value})}
                >
                  <option value="">Wählen...</option>
                  {tenants.map(t => <option key={t.id} value={t.id}>{t.firstName} {t.lastName}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Objekt</label>
                <select 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.propertyId}
                  onChange={e => setLetterConfig({...letterConfig, propertyId: e.target.value})}
                >
                  <option value="">Wählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Betreff</label>
                <input 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.subject}
                  onChange={e => setLetterConfig({...letterConfig, subject: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Kontext / Grund</label>
                <textarea 
                  className="w-full border p-2 rounded-lg h-24"
                  value={letterConfig.context}
                  onChange={e => setLetterConfig({...letterConfig, context: e.target.value})}
                />
              </div>
              <button 
                onClick={handleGenerateLetter}
                disabled={loading}
                className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition disabled:opacity-50"
              >
                {loading ? <i className="fa-solid fa-spinner fa-spin mr-2"></i> : <i className="fa-solid fa-wand-magic-sparkles mr-2"></i>}
                Brief entwerfen
              </button>
            </div>
          </div>
        )}

        {activeTab === 'expose' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg">
                <i className="fa-solid fa-file-pdf text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Exposé Assistent</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Immobilie wählen</label>
                <select 
                  className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                  value={exposeConfig.propertyId}
                  onChange={e => setExposeConfig({...exposeConfig, propertyId: e.target.value})}
                >
                  <option value="">Objekt auswählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name} ({p.address})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Zweck</label>
                  <select 
                    className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                    value={exposeConfig.purpose}
                    onChange={e => setExposeConfig({...exposeConfig, purpose: e.target.value as any})}
                  >
                    <option value="Vermietung">Vermietung</option>
                    <option value="Verkauf">Verkauf</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Schreibstil</label>
                  <select 
                    className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                    value={exposeConfig.tone}
                    onChange={e => setExposeConfig({...exposeConfig, tone: e.target.value})}
                  >
                    <option value="Modern & Begeisternd">Modern & Begeisternd</option>
                    <option value="Sachlich & Professionell">Sachlich & Professionell</option>
                    <option value="Exklusiv & Edel">Exklusiv & Edel</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Zielgruppe</label>
                <input 
                  className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                  placeholder="z.B. Junge Familien, Studenten, Investoren"
                  value={exposeConfig.targetGroup}
                  onChange={e => setExposeConfig({...exposeConfig, targetGroup: e.target.value})}
                />
              </div>

              <button 
                onClick={handleGenerateExposeClick}
                disabled={loading || !exposeConfig.propertyId}
                className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition disabled:opacity-50 disabled:shadow-none"
              >
                {loading ? (
                  <><i className="fa-solid fa-spinner fa-spin mr-2"></i> Erstelle Exposé...</>
                ) : (
                  <><i className="fa-solid fa-wand-sparkles mr-2"></i> Exposé generieren</>
                )}
              </button>
            </div>
          </div>
        )}

        {activeTab === 'utility' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-amber-100 text-amber-600 p-2 rounded-lg">
                <i className="fa-solid fa-calculator text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Betriebskostenabrechnung</h3>
            </div>

            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Objekt</label>
                  <select 
                    className="w-full border p-2 rounded-lg"
                    value={utilityConfig.propertyId}
                    onChange={e => setUtilityConfig({...utilityConfig, propertyId: e.target.value})}
                  >
                    <option value="">Wählen...</option>
                    {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Jahr</label>
                  <select 
                    className="w-full border p-2 rounded-lg"
                    value={utilityConfig.year}
                    onChange={e => setUtilityConfig({...utilityConfig, year: e.target.value})}
                  >
                    <option value="2023">2023</option>
                    <option value="2024">2024</option>
                  </select>
                </div>
              </div>

              {utilityReport && (
                <div className="mt-6 border-t pt-6">
                  <div className="flex justify-between items-center mb-4">
                    <h4 className="font-bold text-slate-800">Kalkulationsübersicht</h4>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-500">Umlage nach Fläche</span>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-xl mb-4 text-sm grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-slate-500">Gesamtausgaben:</p>
                      <p className="font-bold text-slate-800">{utilityReport.totalExpenses.toFixed(2)} €</p>
                    </div>
                    <div>
                      <p className="text-slate-500">Kosten pro m²:</p>
                      <p className="font-bold text-slate-800">{utilityReport.costPerM2.toFixed(4)} €</p>
                    </div>
                  </div>

                  <div className="space-y-2">
                    {utilityReport.unitDetails.map((detail, idx) => (
                      <div key={idx} className="p-3 bg-white border border-slate-100 rounded-lg text-sm flex items-center justify-between">
                        <div>
                          <p className="font-bold">{detail.unit.number}</p>
                          <p className="text-xs text-slate-500">
