                          {detail.tenant && (
                            <button 
                              onClick={() => handleGenerateUtilityLetter(detail)}
                              className="text-[10px] text-indigo-600 font-bold hover:underline"
                            >
                              Anschreiben generieren
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-h-[400px] flex flex-col">
        <h3 className="text-lg font-bold mb-4 border-b border-slate-100 pb-2">Vorschau / Ergebnis</h3>
        {loading ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <div className="relative">
              <i className="fa-solid fa-robot text-6xl mb-4 animate-pulse text-indigo-200"></i>
              <i className="fa-solid fa-sparkles text-2xl absolute top-0 -right-2 text-indigo-500 animate-bounce"></i>
            </div>
            <p className="font-bold text-slate-600">KI erstellt Ihr Dokument...</p>
            <p className="text-xs text-slate-400 mt-1">Dies kann einen Moment dauern.</p>
          </div>
        ) : result ? (
          <div className="flex-1 overflow-y-auto whitespace-pre-wrap text-sm text-slate-700 leading-relaxed font-serif bg-slate-50 p-6 md:p-10 rounded-xl border border-slate-200 shadow-inner">
            <div className="prose prose-slate max-w-none">
              {result}
            </div>
            <div className="mt-12 pt-6 border-t border-slate-200 flex flex-wrap gap-3 no-print">
              <button 
                onClick={() => window.print()} 
                className="bg-slate-800 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-slate-900 transition flex items-center"
              >
                <i className="fa-solid fa-print mr-2"></i> Drucken / PDF
              </button>
              <button 
                onClick={() => {
                  navigator.clipboard.writeText(result);
                  alert('In die Zwischenablage kopiert!');
                }} 
                className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-indigo-700 transition flex items-center"
              >
                <i className="fa-solid fa-copy mr-2"></i> Kopieren
              </button>
              <button 
                onClick={() => setResult('')} 
                className="bg-white border border-slate-200 text-slate-500 px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-slate-50 transition"
              >
                Schließen
              </button>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-300 italic text-center px-12">
            <i className="fa-solid fa-pen-nib text-4xl mb-4 opacity-20"></i>
            <p className="text-sm">Wählen Sie links eine Immobilie und die gewünschten Optionen aus, um ein überzeugendes Exposé oder Anschreiben zu erstellen.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AITools;

import { GoogleGenAI } from "@google/genai";
import { Property, Tenant } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateTenantLetter = async (
  tenant: Tenant,
  property: Property,
  subject: string,
  context: string
): Promise<string> => {
  const prompt = `Erstelle einen formellen Brief an einen Mieter auf Deutsch.
  Absender: Vermieter
  Empfänger: ${tenant.firstName} ${tenant.lastName}, wohnhaft in ${property.address}
  Betreff: ${subject}
  Zusatzinfo: ${context}
  Der Ton soll professionell, höflich aber bestimmt sein. Verwende das aktuelle Datum.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, der Brief konnte nicht generiert werden.";
  }
};

export const generateExpose = async (
  property: Property, 
  purpose: 'Vermietung' | 'Verkauf' = 'Vermietung',
  targetGroup: string = 'Allgemein',
  tone: string = 'Modern & Begeisternd'
): Promise<string> => {
  const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
  const unitCount = property.units.length;

  const prompt = `Erstelle ein hochprofessionelles und überzeugendes Immobilien-Exposé für folgendes Objekt:

  DETAILS:
  Name: ${property.name}
  Typ: ${property.type}
  Adresse: ${property.address}
  Einheiten: ${unitCount}
  Gesamtfläche: ${totalArea} m²

  KONFIGURATION:
  Zweck: ${purpose}
  Zielgruppe: ${targetGroup}
  Schreibstil: ${tone}

  ANFORDERUNGEN:
  1. Erstelle eine packende Überschrift.
  2. Schreibe eine Einleitung, die Emotionen weckt.
  3. Erstelle eine detaillierte Objektbeschreibung basierend auf den Daten.
  4. Beschreibe die Lage (fiktiv, aber passend zur Adresse in ${property.address.split(',').pop()}).
  5. Liste 5 Highlights/Vorteile auf.
  6. Beende mit einem überzeugenden Call-to-Action für die Zielgruppe ${targetGroup}.

  Der Text soll auf Deutsch sein und Layout-Elemente wie Markdown-Überschriften verwenden.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, das Exposé konnte nicht generiert werden.";
  }
};

export const generateUtilityStatementLetter = async (
  tenant: Tenant,
  property: Property,
  year: string,
  totalCosts: number,
  tenantShare: number,
  prepaid: number,
  balance: number,
  breakdown: Record<string, number>
): Promise<string> => {
  const breakdownStr = Object.entries(breakdown)
    .map(([cat, val]) => `- ${cat}: ${val.toFixed(2)}€`)
    .join('\n');

  const prompt = `Erstelle ein formelles Anschreiben zur Betriebskostenabrechnung für das Jahr ${year}.
  Objekt: ${property.name}, ${property.address}
  Mieter: ${tenant.firstName} ${tenant.lastName}

  Finanzielle Details des Gesamtobjekts:
  - Gesamtkosten: ${totalCosts.toFixed(2)}€
  - Kostenstellen-Aufschlüsselung:
${breakdownStr}

  Details für diesen Mieter:
  - Anteil des Mieters: ${tenantShare.toFixed(2)}€
  - Geleistete Vorauszahlungen: ${prepaid.toFixed(2)}€
  - Ergebnis: ${balance > 0 ? `Nachzahlung von ${balance.toFixed(2)}€` : `Guthaben von ${Math.abs(balance).toFixed(2)}€`}

  Bitte erstelle einen professionellen Brief, der die Gesamtkosten kurz erwähnt und die individuelle Berechnung erläutert. Weise höflich auf die Nachzahlung oder das Guthaben hin. Nenne eine Frist von 30 Tagen. Verwende ein sauberes Layout mit Markdown.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, das Anschreiben konnte nicht generiert werden.";
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Tenant, Transaction, TransactionType } from '../types';
import { generateTenantLetter, generateExpose, generateUtilityStatementLetter } from '../services/geminiService';

interface AIToolsProps {
  properties: Property[];
  tenants: Tenant[];
  transactions: Transaction[];
  initialPropertyId?: string;
}

const AITools: React.FC<AIToolsProps> = ({ properties, tenants, transactions, initialPropertyId }) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');
  const [activeTab, setActiveTab] = useState<'letter' | 'expose' | 'utility'>('letter');

  const [letterConfig, setLetterConfig] = useState({
    tenantId: '',
    propertyId: '',
    subject: 'Mieterhöhung gemäß Mietspiegel',
    context: 'Die letzte Erhöhung war vor 3 Jahren. Wir müssen an den aktuellen Marktwert anpassen.'
  });

  const [utilityConfig, setUtilityConfig] = useState({
    propertyId: '',
    year: '2023'
  });

  const [exposeConfig, setExposeConfig] = useState({
    propertyId: '',
    purpose: 'Vermietung' as 'Vermietung' | 'Verkauf',
    targetGroup: 'Junge Familien',
    tone: 'Modern & Begeisternd'
  });

  // Handle deep-linking / pre-selection
  useEffect(() => {
    if (initialPropertyId) {
      setActiveTab('expose');
      setExposeConfig(prev => ({ ...prev, propertyId: initialPropertyId }));
    }
  }, [initialPropertyId]);

  // Enhanced Calculation Logic for Utility Statement
  const utilityReport = useMemo(() => {
    if (!utilityConfig.propertyId) return null;

    const property = properties.find(p => p.id === utilityConfig.propertyId);
    if (!property) return null;

    const propertyExpenses = transactions.filter(t => 
      t.propertyId === utilityConfig.propertyId && 
      t.type === TransactionType.EXPENSE &&
      t.date.startsWith(utilityConfig.year)
    );

    const totalExpenses = propertyExpenses.reduce((sum, t) => sum + t.amount, 0);
    const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
    const costPerM2 = totalArea > 0 ? totalExpenses / totalArea : 0;

    // Category breakdown
    const categories: Record<string, number> = {};
    propertyExpenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });

    const unitDetails = property.units.map(u => {
      const tenant = tenants.find(t => t.id === u.tenantId);
      const share = u.size * costPerM2;
      const prepaid = u.utilityPrepayment * 12; // Assuming full year
      const balance = share - prepaid;

      return {
        unit: u,
        tenant,
        share,
        prepaid,
        balance
      };
    });

    return {
      property,
      totalExpenses,
      totalArea,
      costPerM2,
      categories,
      unitDetails
    };
  }, [utilityConfig, properties, transactions, tenants]);

  const handleGenerateLetter = async () => {
    const tenant = tenants.find(t => t.id === letterConfig.tenantId);
    const property = properties.find(p => p.id === letterConfig.propertyId);
    if (!tenant || !property) return alert('Bitte Mieter und Objekt wählen.');

    setLoading(true);
    const text = await generateTenantLetter(tenant, property, letterConfig.subject, letterConfig.context);
    setResult(text);
    setLoading(false);
  };

  const handleGenerateExposeClick = async () => {
    const property = properties.find(p => p.id === exposeConfig.propertyId);
    if (!property) return alert('Bitte ein Objekt wählen.');

    setLoading(true);
    const text = await generateExpose(
      property, 
      exposeConfig.purpose, 
      exposeConfig.targetGroup, 
      exposeConfig.tone
    );
    setResult(text);
    setLoading(false);
  };

  const handleGenerateUtilityLetter = async (detail: any) => {
    if (!detail.tenant || !utilityReport) return;
    setLoading(true);
    const text = await generateUtilityStatementLetter(
      detail.tenant,
      utilityReport.property,
      utilityConfig.year,
      utilityReport.totalExpenses,
      detail.share,
      detail.prepaid,
      detail.balance,
      utilityReport.categories
    );
    setResult(text);
    setLoading(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-xl shadow-sm border border-slate-100 mb-2 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('letter')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'letter' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Anschreiben
          </button>
          <button 
            onClick={() => setActiveTab('expose')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'expose' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Exposé
          </button>
          <button 
            onClick={() => setActiveTab('utility')}
            className={`flex-1 min-w-[100px] py-2 px-4 rounded-lg text-sm font-bold transition ${activeTab === 'utility' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Abrechnung
          </button>
        </div>

        {activeTab === 'letter' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-indigo-100 text-indigo-600 p-2 rounded-lg">
                <i className="fa-solid fa-envelope-open-text text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Briefvorlage generieren</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Mieter</label>
                <select 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.tenantId}
                  onChange={e => setLetterConfig({...letterConfig, tenantId: e.target.value})}
                >
                  <option value="">Wählen...</option>
                  {tenants.map(t => <option key={t.id} value={t.id}>{t.firstName} {t.lastName}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Objekt</label>
                <select 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.propertyId}
                  onChange={e => setLetterConfig({...letterConfig, propertyId: e.target.value})}
                >
                  <option value="">Wählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Betreff</label>
                <input 
                  className="w-full border p-2 rounded-lg"
                  value={letterConfig.subject}
                  onChange={e => setLetterConfig({...letterConfig, subject: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Kontext / Grund</label>
                <textarea 
                  className="w-full border p-2 rounded-lg h-24"
                  value={letterConfig.context}
                  onChange={e => setLetterConfig({...letterConfig, context: e.target.value})}
                />
              </div>
              <button 
                onClick={handleGenerateLetter}
                disabled={loading}
                className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition disabled:opacity-50"
              >
                {loading ? <i className="fa-solid fa-spinner fa-spin mr-2"></i> : <i className="fa-solid fa-wand-magic-sparkles mr-2"></i>}
                Brief entwerfen
              </button>
            </div>
          </div>
        )}

        {activeTab === 'expose' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg">
                <i className="fa-solid fa-file-pdf text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Exposé Assistent</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Immobilie wählen</label>
                <select 
                  className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                  value={exposeConfig.propertyId}
                  onChange={e => setExposeConfig({...exposeConfig, propertyId: e.target.value})}
                >
                  <option value="">Objekt auswählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name} ({p.address})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Zweck</label>
                  <select 
                    className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                    value={exposeConfig.purpose}
                    onChange={e => setExposeConfig({...exposeConfig, purpose: e.target.value as any})}
                  >
                    <option value="Vermietung">Vermietung</option>
                    <option value="Verkauf">Verkauf</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Schreibstil</label>
                  <select 
                    className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                    value={exposeConfig.tone}
                    onChange={e => setExposeConfig({...exposeConfig, tone: e.target.value})}
                  >
                    <option value="Modern & Begeisternd">Modern & Begeisternd</option>
                    <option value="Sachlich & Professionell">Sachlich & Professionell</option>
                    <option value="Exklusiv & Edel">Exklusiv & Edel</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Zielgruppe</label>
                <input 
                  className="w-full border p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500"
                  placeholder="z.B. Junge Familien, Studenten, Investoren"
                  value={exposeConfig.targetGroup}
                  onChange={e => setExposeConfig({...exposeConfig, targetGroup: e.target.value})}
                />
              </div>

              <button 
                onClick={handleGenerateExposeClick}
                disabled={loading || !exposeConfig.propertyId}
                className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition disabled:opacity-50 disabled:shadow-none"
              >
                {loading ? (
                  <><i className="fa-solid fa-spinner fa-spin mr-2"></i> Erstelle Exposé...</>
                ) : (
                  <><i className="fa-solid fa-wand-sparkles mr-2"></i> Exposé generieren</>
                )}
              </button>
            </div>
          </div>
        )}

        {activeTab === 'utility' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-amber-100 text-amber-600 p-2 rounded-lg">
                <i className="fa-solid fa-calculator text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Betriebskostenabrechnung</h3>
            </div>

            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Objekt</label>
                  <select 
                    className="w-full border p-2 rounded-lg"
                    value={utilityConfig.propertyId}
                    onChange={e => setUtilityConfig({...utilityConfig, propertyId: e.target.value})}
                  >
                    <option value="">Wählen...</option>
                    {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Jahr</label>
                  <select 
                    className="w-full border p-2 rounded-lg"
                    value={utilityConfig.year}
                    onChange={e => setUtilityConfig({...utilityConfig, year: e.target.value})}
                  >
                    <option value="2023">2023</option>
                    <option value="2024">2024</option>
                  </select>
                </div>
              </div>

              {utilityReport && (
                <div className="mt-6 border-t pt-6">
                  <div className="flex justify-between items-center mb-4">
                    <h4 className="font-bold text-slate-800">Kalkulationsübersicht</h4>
                    <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-500">Umlage nach Fläche</span>
                  </div>

                  <div className="bg-slate-50 p-4 rounded-xl mb-6 text-sm grid grid-cols-2 gap-4">
                    <div className="col-span-2 flex justify-between border-b border-slate-200 pb-2 mb-2">
                      <span className="font-bold text-slate-700">Gesamtausgaben {utilityConfig.year}:</span>
                      <span className="font-bold text-indigo-600 text-lg">{utilityReport.totalExpenses.toFixed(2)} €</span>
                    </div>
                    {Object.entries(utilityReport.categories).map(([cat, val]) => (
                      <div key={cat} className="flex justify-between items-center bg-white p-2 rounded-lg border border-slate-200 shadow-sm">
                        <span className="text-xs text-slate-500 truncate mr-2">{cat}:</span>
                        <span className="text-xs font-bold text-slate-700">{val.toFixed(2)}€</span>
                      </div>
                    ))}
                    <div className="col-span-2 pt-2 text-[10px] text-slate-400 font-medium">
                      Berechnet für {utilityReport.totalArea} m² Gesamtfläche • {utilityReport.costPerM2.toFixed(4)} € pro m²
                    </div>
                  </div>

                  <div className="space-y-3">
                    <h5 className="text-xs font-black text-slate-400 uppercase tracking-widest">Mieteranteile</h5>
                    {utilityReport.unitDetails.map((detail, idx) => (
                      <div key={idx} className="p-4 bg-white border border-slate-100 rounded-xl shadow-sm flex items-center justify-between hover:border-indigo-200 transition">
                        <div className="flex-1">
                          <p className="font-bold text-slate-800">{detail.unit.number}</p>
                          <p className="text-xs text-slate-500">
                            {detail.tenant ? `${detail.tenant.firstName} ${detail.tenant.lastName}` : 'Unbelegt'}
                          </p>
                          <div className="mt-2 text-[10px] flex space-x-3 text-slate-400">
                            <span>Soll: {detail.share.toFixed(2)}€</span>
                            <span>Ist: {detail.prepaid.toFixed(2)}€</span>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className={`text-sm font-black ${detail.balance > 0 ? 'text-red-600' : 'text-emerald-600'}`}>
                            {detail.balance > 0 ? '+' : ''}{detail.balance.toFixed(2)} €
                          </p>
                          <p className="text-[10px] text-slate-400 uppercase font-bold mb-2">
                            {detail.balance > 0 ? 'Nachzahlung' : 'Guthaben'}
                          </p>
                          {detail.tenant && (
                            <button 
                              onClick={() => handleGenerateUtilityLetter(detail)}
                              className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg text-[10px] font-bold hover:bg-indigo-100 transition whitespace-nowrap"
                            >
                              KI-Anschreiben
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-h-[400px] flex flex-col">
        <h3 className="text-lg font-bold mb-4 border-b border-slate-100 pb-2 flex justify-between items-center">
          Vorschau / Ergebnis
          {result && (
            <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full animate-pulse">
              Generiert
            </span>
          )}
        </h3>
        {loading ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <div className="relative">
              <i className="fa-solid fa-robot text-6xl mb-4 animate-pulse text-indigo-200"></i>
              <i className="fa-solid fa-sparkles text-2xl absolute top-0 -right-2 text-indigo-500 animate-bounce"></i>
            </div>
            <p className="font-bold text-slate-600 text-center px-6">KI erstellt ein detailliertes Dokument...</p>
            <p className="text-xs text-slate-400 mt-1">Die Berechnungen werden verarbeitet.</p>
          </div>
        ) : result ? (
          <div className="flex-1 overflow-y-auto whitespace-pre-wrap text-sm text-slate-700 leading-relaxed font-serif bg-white p-6 md:p-10 rounded-xl border border-slate-200 shadow-inner">
            <div className="prose prose-slate max-w-none">
              {result}
            </div>
            <div className="mt-12 pt-6 border-t border-slate-200 flex flex-wrap gap-3 no-print">
              <button 
                onClick={() => window.print()} 
                className="bg-slate-800 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-slate-900 transition flex items-center"
              >
                <i className="fa-solid fa-print mr-2"></i> Drucken / PDF
              </button>
              <button 
                onClick={() => {
                  navigator.clipboard.writeText(result);
                  alert('In die Zwischenablage kopiert!');
                }} 
                className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-indigo-700 transition flex items-center"
              >
                <i className="fa-solid fa-copy mr-2"></i> Kopieren
              </button>
              <button 
                onClick={() => setResult('')} 
                className="bg-white border border-slate-200 text-slate-500 px-5 py-2.5 rounded-xl text-xs font-bold hover:bg-slate-50 transition"
              >
                Schließen
              </button>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-300 italic text-center px-12">
            <div className="bg-slate-50 p-8 rounded-full mb-6">
              <i className="fa-solid fa-pen-nib text-4xl opacity-20"></i>
            </div>
            <h4 className="text-slate-500 font-bold mb-2">Bereit zur Erstellung</h4>
            <p className="text-sm">Konfigurieren Sie links die Details. Die KI wird automatisch alle Berechnungen (Flächenschlüssel, Vorauszahlungen, Salden) in ein professionelles Anschreiben einbetten.</p>
          </div>
        )}
      </div>
    </div>
  );
};

