            </div>
          </form>
        </div>
      )}

      {/* Card View for Mobile */}
      <div className="lg:hidden space-y-4">
        {transactions.length > 0 ? (
          transactions.slice().sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => (
            <div key={t.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
              <div className={`p-3 rounded-xl ${t.type === TransactionType.INCOME ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                <i className={`fa-solid ${t.type === TransactionType.INCOME ? 'fa-arrow-trend-up' : 'fa-arrow-trend-down'}`}></i>
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-start">
                  <h4 className="font-bold text-slate-800 truncate">{t.description}</h4>
                  <span className={`text-sm font-black whitespace-nowrap ml-2 ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-red-600'}`}>
                    {t.type === TransactionType.INCOME ? '+' : '-'}{t.amount.toLocaleString('de-DE', { minimumFractionDigits: 2 })} €
                  </span>
                </div>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wide">
                  {t.date} • {properties.find(p => p.id === t.propertyId)?.name || 'Unbekannt'}
                </p>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-slate-200 text-slate-400 italic text-sm">Keine Transaktionen gefunden.</div>
        )}
      </div>

      {/* Table View for Desktop */}
      <div className="hidden lg:block bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 text-xs font-bold uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Datum</th>
              <th className="px-6 py-4">Objekt</th>
              <th className="px-6 py-4">Kategorie / Beschreibung</th>
              <th className="px-6 py-4 text-right">Betrag</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.length > 0 ? (
              transactions.slice().sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()).map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition">
                  <td className="px-6 py-4 text-sm text-slate-600">{t.date}</td>
                  <td className="px-6 py-4 text-sm font-medium text-slate-800">
                    {properties.find(p => p.id === t.propertyId)?.name || 'Unbekannt'}
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm font-semibold text-slate-800">{t.category}</p>
                    <p className="text-xs text-slate-500">{t.description}</p>
                  </td>
                  <td className={`px-6 py-4 text-right font-bold ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-red-600'}`}>
                    {t.type === TransactionType.INCOME ? '+' : '-'}{t.amount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={4} className="px-6 py-12 text-center text-slate-400">Keine Transaktionen gefunden.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

