import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Property, Tenant, Transaction, TransactionType, MeterType, MeterReading } from '../types';
import { generateTenantLetter, generateExpose, generateUtilityStatementLetter, extractMeterData } from '../services/geminiService';

interface AIToolsProps {
  properties: Property[];
  tenants: Tenant[];
  transactions: Transaction[];
  initialPropertyId?: string;
}

interface PortalStatus {
  id: string;
  name: string;
  connected: boolean;
  lastSync?: string;
  color: string;
  icon: string;
}

const AITools: React.FC<AIToolsProps> = ({ properties, tenants, transactions, initialPropertyId }) => {
  const [loading, setLoading] = useState(false);
  const [publishing, setPublishing] = useState(false);
  const [publishProgress, setPublishProgress] = useState(0);
  const [result, setResult] = useState('');
  const [activeTab, setActiveTab] = useState<'letter' | 'expose' | 'utility' | 'portals' | 'meters'>('letter');

  const [portals, setPortals] = useState<PortalStatus[]>([
    { id: 'is24', name: 'ImmoScout24', connected: false, color: 'bg-orange-500', icon: 'fa-house-chimney' },
    { id: 'immonet', name: 'Immonet', connected: false, color: 'bg-blue-600', icon: 'fa-globe' },
    { id: 'immowelt', name: 'Immowelt', connected: false, color: 'bg-pink-600', icon: 'fa-door-open' }
  ]);

  const [letterConfig, setLetterConfig] = useState({
    tenantId: '',
    propertyId: '',
    subject: 'Mieterhöhung gemäß Mietspiegel',
    context: 'Die letzte Erhöhung war vor 3 Jahren. Wir müssen an den aktuellen Marktwert anpassen.'
  });

  const [utilityConfig, setUtilityConfig] = useState({
    propertyId: '',
    year: '2023'
  });

  const [exposeConfig, setExposeConfig] = useState({
    propertyId: '',
    purpose: 'Vermietung' as 'Vermietung' | 'Verkauf',
    targetGroup: 'Junge Familien',
    tone: 'Modern & Begeisternd',
    highlights: ''
  });

  // Meter Reading States
  const [showCamera, setShowCamera] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [extractedMeter, setExtractedMeter] = useState<{ type: MeterType; value: number; serialNumber: string; unit: string } | null>(null);
  const [meterPropertyId, setMeterPropertyId] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const targetGroups = [
    'Junge Familien', 'Studenten & WGs', 'Singles & Berufstätige', 
    'Senioren / Barrierefrei', 'Kapitalanleger & Investoren', 
    'Exklusive Klientel', 'Pendler'
  ];

  const tones = [
    'Modern & Begeisternd', 'Sachlich & Professionell', 
    'Exklusiv & Luxuriös', 'Herzlich & Einladend', 
    'Dringend & Aktivierend', 'Kurz & Prägnant'
  ];

  useEffect(() => {
    if (initialPropertyId) {
      setActiveTab('expose');
      setExposeConfig(prev => ({ ...prev, propertyId: initialPropertyId }));
    }
  }, [initialPropertyId]);

  const utilityReport = useMemo(() => {
    if (!utilityConfig.propertyId) return null;
    const property = properties.find(p => p.id === utilityConfig.propertyId);
    if (!property) return null;
    const propertyExpenses = transactions.filter(t => 
      t.propertyId === utilityConfig.propertyId && 
      t.type === TransactionType.EXPENSE &&
      t.date.startsWith(utilityConfig.year)
    );
    const totalExpenses = propertyExpenses.reduce((sum, t) => sum + t.amount, 0);
    const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
    const costPerM2 = totalArea > 0 ? totalExpenses / totalArea : 0;
    const categories: Record<string, number> = {};
    propertyExpenses.forEach(t => { categories[t.category] = (categories[t.category] || 0) + t.amount; });
    const unitDetails = property.units.map(u => {
      const tenant = tenants.find(t => t.id === u.tenantId);
      const share = u.size * costPerM2;
      const prepaid = u.utilityPrepayment * 12;
      return { unit: u, tenant, share, prepaid, balance: share - prepaid };
    });
    return { property, totalExpenses, totalArea, costPerM2, categories, unitDetails };
  }, [utilityConfig, properties, transactions, tenants]);

  const handleGenerateExposeClick = async () => {
    const property = properties.find(p => p.id === exposeConfig.propertyId);
    if (!property) return alert('Bitte ein Objekt wählen.');
    setLoading(true);
    const text = await generateExpose(property, exposeConfig.purpose, exposeConfig.targetGroup, exposeConfig.tone, exposeConfig.highlights);
    setResult(text);
    setLoading(false);
  };

  const handlePublish = async (portalId: string) => {
    const portal = portals.find(p => p.id === portalId);
    if (!portal?.connected) return alert('Bitte verknüpfen Sie zuerst Ihr Konto im Reiter "Portale".');
    setPublishing(true);
    setPublishProgress(10);
    const steps = [25, 45, 70, 90, 100];
    for (let step of steps) {
      await new Promise(r => setTimeout(r, 600));
      setPublishProgress(step);
    }
    setTimeout(() => {
      setPublishing(false);
      setPublishProgress(0);
      alert(`${portal.name}: Exposé erfolgreich veröffentlicht!`);
    }, 500);
  };

  const togglePortalConnection = (id: string) => {
    setPortals(prev => prev.map(p => 
      p.id === id ? { ...p, connected: !p.connected, lastSync: !p.connected ? new Date().toLocaleDateString() : undefined } : p
    ));
  };

  // Camera Logic
  const startCamera = async () => {
    setShowCamera(true);
    setCapturedImage(null);
    setExtractedMeter(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera error:", err);
      alert("Kamerazugriff verweigert.");
      setShowCamera(false);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(video, 0, 0);
      const dataUrl = canvas.toDataURL('image/jpeg');
      setCapturedImage(dataUrl);

      // Stop stream
      const stream = video.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      setShowCamera(false);

      handleExtractMeter(dataUrl);
    }
  };

