import { GoogleGenAI, Type } from "@google/genai";
import { Property, Tenant, ContractAnalysis, MeterType, MarketData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchMarketAnalysis = async (property: Property): Promise<MarketData | null> => {
  const prompt = `Führe eine Marktanalyse für folgende Immobilie durch:
  Adresse: ${property.address}
  Typ: ${property.type}

  Suche auf Immobilienportalen nach:
  1. Durchschnittlicher Mietpreis pro m² (kalt) in dieser Lage.
  2. Durchschnittlicher Verkaufspreis pro m² in dieser Lage.
  3. Aktueller Markttrend für diesen Standort.

  Antworte in einem validen JSON-Format mit folgenden Feldern:
  averageRentPerM2 (Zahl), averageSalePerM2 (Zahl), marketTrend ('rising', 'stable', 'falling'), summary (Text).`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Pro model for Search Tool
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "";
    // Extract JSON from markdown if needed
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    const data = jsonMatch ? JSON.parse(jsonMatch[0]) : {};

    // Extract Grounding Sources
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Quelle",
        uri: chunk.web?.uri || ""
      }))
      .filter((s: any) => s.uri) || [];

    return {
      averageRentPerM2: data.averageRentPerM2 || 0,
      averageSalePerM2: data.averageSalePerM2 || 0,
      marketTrend: data.marketTrend || 'stable',
      summary: data.summary || text,
      sources: sources
    };
  } catch (error) {
    console.error("Market Analysis Error:", error);
    return null;
  }
};

export const extractMeterData = async (
  base64Image: string,
  mimeType: string
): Promise<{ type: MeterType; value: number; serialNumber: string; unit: string } | null> => {
  const data = base64Image.split(',')[1] || base64Image;

  const prompt = `Analysiere dieses Bild eines Zählers (Strom, Gas oder Wasser). 
  Extrahiere folgende Informationen:
  1. Typ des Zählers (Strom, Gas oder Wasser)
  2. Aktueller Zählerstand (nur die Ziffern vor dem Komma/den roten Feldern)
  3. Die Zählernummer (Seriennummer auf dem Gerät)
  4. Die Einheit (kWh oder m³)

  Gib das Ergebnis strikt als JSON zurück.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { text: prompt },
        { inlineData: { data, mimeType } }
      ],
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING, enum: ['Strom', 'Gas', 'Wasser'] },
            value: { type: Type.NUMBER },
            serialNumber: { type: Type.STRING },
            unit: { type: Type.STRING }
          },
          required: ['type', 'value', 'unit']
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Meter Extraction Error:", error);
    return null;
  }
};

export const generateTenantLetter = async (
  tenant: Tenant,
  property: Property,
  subject: string,
  context: string
): Promise<string> => {
  const prompt = `Erstelle einen formellen Brief an einen Mieter auf Deutsch.
  Absender: Vermieter
  Empfänger: ${tenant.firstName} ${tenant.lastName}, wohnhaft in ${property.address}
  Betreff: ${subject}
  Zusatzinfo: ${context}
  Der Ton soll professionell, höflich aber bestimmt sein. Verwende das aktuelle Datum.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, der Brief konnte nicht generiert werden.";
  }
};

export const generateExpose = async (
  property: Property, 
  purpose: 'Vermietung' | 'Verkauf' = 'Vermietung',
  targetGroup: string = 'Allgemein',
  tone: string = 'Modern & Begeisternd',
  highlights: string = ''
): Promise<string> => {
  const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
  const unitCount = property.units.length;

  const prompt = `Erstelle ein hochprofessionelles und überzeugendes Immobilien-Exposé für folgendes Objekt:

  DETAILS:
  Name: ${property.name}
  Typ: ${property.type}
  Adresse: ${property.address}
  Einheiten: ${unitCount}
  Gesamtfläche: ${totalArea} m²
  ${highlights ? `BESONDERE HIGHLIGHTS: ${highlights}` : ''}

  KONFIGURATION:
  Zweck: ${purpose}
  Zielgruppe: ${targetGroup}
  Schreibstil: ${tone}

  STRUKTUR & ANFORDERUNGEN:
  1. Eine fesselnde Headline, die genau auf ${targetGroup} zugeschnitten ist.
  2. Einleitung: Wecke Begehrlichkeiten und nutze den Stil "${tone}".
  3. Objektbeschreibung: Nutze die harten Fakten (${totalArea} m², ${unitCount} Einheiten).
  4. Highlights: Gehe besonders auf ${highlights || 'die Qualität des Objekts'} ein.
  5. Lagebericht: Beschreibe die Vorzüge der Lage in ${property.address} (Infrastruktur, Lebensqualität).
  6. Call-to-Action: Ein starker Abschluss, der zur Kontaktaufnahme auffordert.

  Sprache: Deutsch. Formatierung: Nutze Markdown für eine schöne Struktur (Überschriften, Fettschrift, Aufzählungszeichen).`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, das Exposé konnte nicht generiert werden.";
  }
};

export const generateUtilityStatementLetter = async (
  tenant: Tenant,
  property: Property,
  year: string,
  totalCosts: number,
  tenantShare: number,
  prepaid: number,
  balance: number,
  breakdown: Record<string, number>
): Promise<string> => {
  const breakdownStr = Object.entries(breakdown)
    .map(([cat, val]) => `- ${cat}: ${val.toFixed(2)}€`)
    .join('\n');

  const prompt = `Erstelle ein formelles Anschreiben zur Betriebskostenabrechnung für das Jahr ${year}.
  Objekt: ${property.name}, ${property.address}
  Mieter: ${tenant.firstName} ${tenant.lastName}

  Finanzielle Details des Gesamtobjekts:
  - Gesamtkosten: ${totalCosts.toFixed(2)}€
  - Kostenstellen-Aufschlüsselung:
${breakdownStr}

  Details für diesen Mieter:
  - Anteil des Mieters: ${tenantShare.toFixed(2)}€
  - Geleistete Vorauszahlungen: ${prepaid.toFixed(2)}€
  - Ergebnis: ${balance > 0 ? `Nachzahlung von ${balance.toFixed(2)}€` : `Guthaben von ${Math.abs(balance).toFixed(2)}€`}

  Bitte erstelle einen professionellen Brief, der die Gesamtkosten kurz erwähnt und die individuelle Berechnung erläutert. Weise höflich auf die Nachzahlung oder das Guthaben hin. Nenne eine Frist von 30 Tagen. Verwende ein sauberes Layout mit Markdown.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Fehler bei der Generierung.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Entschuldigung, das Anschreiben konnte nicht generiert werden.";
  }
};

export const analyzeContract = async (
  fileData: string, 
  mimeType: string
): Promise<ContractAnalysis | null> => {
  const base64Data = fileData.split(',')[1] || fileData;

  const prompt = `Analysiere diesen Mietvertrag und extrahiere die wichtigsten Informationen. 
  Bitte identifiziere:
  - Mietbeginn
  - Mietende (falls befristet)
  - Miethöhe (Kaltmiete)
  - Kündigungsfrist
  - Ungewöhnliche oder problematische Klauseln
  - Potenzielle Risiken für den Vermieter
  - Eine kurze Zusammenfassung des Vertrags.

  Gib die Antwort in strukturiertem JSON-Format zurück.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { text: prompt },
        { inlineData: { data: base64Data, mimeType: mimeType } }
      ],
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            leaseStart: { type: Type.STRING },
            leaseEnd: { type: Type.STRING },
            rentAmount: { type: Type.STRING },
            noticePeriod: { type: Type.STRING },
            unusualClauses: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            risks: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            summary: { type: Type.STRING }
          },
          required: ['unusualClauses', 'risks', 'summary']
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as ContractAnalysis;
  } catch (error) {
    console.error("Contract Analysis Error:", error);
    return null;
  }
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Property, Tenant, Transaction, TransactionType, MeterType, MarketData } from '../types';
import { generateTenantLetter, generateExpose, generateUtilityStatementLetter, extractMeterData, fetchMarketAnalysis } from '../services/geminiService';

interface AIToolsProps {
  properties: Property[];
  tenants: Tenant[];
  transactions: Transaction[];
  initialPropertyId?: string;
}

interface PortalStatus {
  id: string;
  name: string;
  connected: boolean;
  lastSync?: string;
  color: string;
  icon: string;
}

const AITools: React.FC<AIToolsProps> = ({ properties, tenants, transactions, initialPropertyId }) => {
  const [loading, setLoading] = useState(false);
  const [publishing, setPublishing] = useState(false);
  const [publishProgress, setPublishProgress] = useState(0);
  const [result, setResult] = useState('');
  const [activeTab, setActiveTab] = useState<'letter' | 'expose' | 'utility' | 'portals' | 'meters' | 'market'>('letter');
  const [marketAnalysis, setMarketAnalysis] = useState<MarketData | null>(null);
  const [selectedPropertyId, setSelectedPropertyId] = useState('');

  const [portals, setPortals] = useState<PortalStatus[]>([
    { id: 'is24', name: 'ImmoScout24', connected: false, color: 'bg-orange-500', icon: 'fa-house-chimney' },
    { id: 'immonet', name: 'Immonet', connected: false, color: 'bg-blue-600', icon: 'fa-globe' },
    { id: 'immowelt', name: 'Immowelt', connected: false, color: 'bg-pink-600', icon: 'fa-door-open' }
  ]);

  const [letterConfig, setLetterConfig] = useState({
    tenantId: '',
    propertyId: '',
    subject: 'Mieterhöhung gemäß Mietspiegel',
    context: 'Die letzte Erhöhung war vor 3 Jahren. Wir müssen an den aktuellen Marktwert anpassen.'
  });

  const [utilityConfig, setUtilityConfig] = useState({
    propertyId: '',
    year: '2023'
  });

  const [exposeConfig, setExposeConfig] = useState({
    propertyId: '',
    purpose: 'Vermietung' as 'Vermietung' | 'Verkauf',
    targetGroup: 'Junge Familien',
    tone: 'Modern & Begeisternd',
    highlights: ''
  });

  // Meter Reading States
  const [showCamera, setShowCamera] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [extractedMeter, setExtractedMeter] = useState<{ type: MeterType; value: number; serialNumber: string; unit: string } | null>(null);
  const [meterPropertyId, setMeterPropertyId] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (initialPropertyId) {
      setActiveTab('expose');
      setExposeConfig(prev => ({ ...prev, propertyId: initialPropertyId }));
    }
  }, [initialPropertyId]);

  const handleMarketCheck = async () => {
    const property = properties.find(p => p.id === selectedPropertyId);
    if (!property) return alert('Bitte Objekt wählen.');
    setLoading(true);
    const data = await fetchMarketAnalysis(property);
    setMarketAnalysis(data);
    setLoading(false);
  };

  const utilityReport = useMemo(() => {
    if (!utilityConfig.propertyId) return null;
    const property = properties.find(p => p.id === utilityConfig.propertyId);
    if (!property) return null;
    const propertyExpenses = transactions.filter(t => 
      t.propertyId === utilityConfig.propertyId && 
      t.type === TransactionType.EXPENSE &&
      t.date.startsWith(utilityConfig.year)
    );
    const totalExpenses = propertyExpenses.reduce((sum, t) => sum + t.amount, 0);
    const totalArea = property.units.reduce((sum, u) => sum + u.size, 0);
    const costPerM2 = totalArea > 0 ? totalExpenses / totalArea : 0;
    const categories: Record<string, number> = {};
    propertyExpenses.forEach(t => { categories[t.category] = (categories[t.category] || 0) + t.amount; });
    const unitDetails = property.units.map(u => {
      const tenant = tenants.find(t => t.id === u.tenantId);
      const share = u.size * costPerM2;
      const prepaid = u.utilityPrepayment * 12;
      return { unit: u, tenant, share, prepaid, balance: share - prepaid };
    });
    return { property, totalExpenses, totalArea, costPerM2, categories, unitDetails };
  }, [utilityConfig, properties, transactions, tenants]);

  // Camera Logic
  const startCamera = async () => {
    setShowCamera(true);
    setCapturedImage(null);
    setExtractedMeter(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera error:", err);
      alert("Kamerazugriff verweigert.");
      setShowCamera(false);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(video, 0, 0);
      const dataUrl = canvas.toDataURL('image/jpeg');
      setCapturedImage(dataUrl);
      const stream = video.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      setShowCamera(false);
      handleExtractMeter(dataUrl);
    }
  };

  const handleExtractMeter = async (img: string) => {
    setLoading(true);
    const data = await extractMeterData(img, 'image/jpeg');
    if (data) setExtractedMeter(data);
    else alert("KI konnte Zähler nicht lesen.");
    setLoading(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        <div className="flex bg-white p-1 rounded-xl shadow-sm border border-slate-100 mb-2 overflow-x-auto scrollbar-hide">
          {[
            { id: 'letter', label: 'Brief' },
            { id: 'expose', label: 'Exposé' },
            { id: 'market', label: 'Markt' },
            { id: 'utility', label: 'Abrechnung' },
            { id: 'meters', label: 'Zähler' },
            { id: 'portals', label: 'Portale' }
          ].map((tab) => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[90px] py-2 px-3 rounded-lg text-xs font-bold transition uppercase tracking-wider ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {activeTab === 'market' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 animate-in fade-in duration-300">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-violet-100 text-violet-600 p-2 rounded-lg">
                <i className="fa-solid fa-magnifying-glass-chart text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Portal-Marktanalyse</h3>
            </div>
            <div className="space-y-4">
              <p className="text-sm text-slate-500">Analysieren Sie die aktuellen Miet- und Verkaufspreise auf Basis von Echtzeit-Daten führender Portale.</p>
              <select 
                className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-violet-500 font-bold"
                value={selectedPropertyId}
                onChange={e => setSelectedPropertyId(e.target.value)}
              >
                <option value="">Objekt wählen...</option>
                {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
              <button 
                onClick={handleMarketCheck} 
                disabled={loading || !selectedPropertyId}
                className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-violet-100 hover:bg-violet-700 transition disabled:opacity-50"
              >
                {loading ? <i className="fa-solid fa-spinner fa-spin mr-2"></i> : <i className="fa-solid fa-earth-europe mr-2"></i>}
                Portaldaten abrufen
              </button>
            </div>
          </div>
        )}

        {/* Existing Tabs */}
        {activeTab === 'meters' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
             <div className="flex items-center space-x-3 mb-6">
              <div className="bg-cyan-100 text-cyan-600 p-2 rounded-lg">
                <i className="fa-solid fa-gauge-high text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Smart Zähler-Scanner</h3>
            </div>
            <div className="space-y-4">
               <select className="w-full border p-2.5 rounded-xl" value={meterPropertyId} onChange={e => setMeterPropertyId(e.target.value)}>
                  <option value="">Wählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
                {!showCamera && !capturedImage && (
                  <div onClick={startCamera} className="border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center cursor-pointer hover:border-cyan-400 hover:bg-cyan-50 transition">
                    <i className="fa-solid fa-camera text-2xl text-cyan-600 mb-2"></i>
                    <p className="font-bold">Zähler scannen</p>
                  </div>
                )}
                {showCamera && (
                   <div className="relative rounded-3xl overflow-hidden bg-black aspect-[3/4]">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <button onClick={capturePhoto} className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-900 w-16 h-16 rounded-full border-4 border-cyan-400"></button>
                   </div>
                )}
                {capturedImage && (
                  <div className="space-y-4">
                    <img src={capturedImage} className="w-full h-48 object-cover rounded-2xl" />
                    {extractedMeter && (
                      <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                        <div className="grid grid-cols-2 gap-2">
                           <div><label className="text-[10px] font-bold text-slate-400">WERT</label><p className="font-black text-xl">{extractedMeter.value} {extractedMeter.unit}</p></div>
                           <div><label className="text-[10px] font-bold text-slate-400">ZÄHLER-NR</label><p className="font-bold">{extractedMeter.serialNumber}</p></div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
            </div>
          </div>
        )}

        {activeTab === 'portals' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Portal-Verknüpfung</h3>
            <div className="space-y-4">
              {portals.map(portal => (
                <div key={portal.id} className="flex items-center justify-between p-4 border rounded-2xl">
                  <span className="font-bold">{portal.name}</span>
                  <button onClick={() => setPortals(prev => prev.map(p => p.id === portal.id ? {...p, connected: !p.connected} : p))} className={`px-4 py-1.5 rounded-lg text-xs font-bold ${portal.connected ? 'bg-red-50 text-red-600' : 'bg-indigo-600 text-white'}`}>
                    {portal.connected ? 'Trennen' : 'Verbinden'}
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'letter' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Mieter-Anschreiben</h3>
            <div className="space-y-4">
              <select className="w-full border p-2 rounded-xl" value={letterConfig.tenantId} onChange={e => setLetterConfig({...letterConfig, tenantId: e.target.value})}>
                <option value="">Mieter...</option>
                {tenants.map(t => <option key={t.id} value={t.id}>{t.firstName} {t.lastName}</option>)}
              </select>
              <textarea className="w-full border p-2 rounded-xl h-24" placeholder="Kontext..." value={letterConfig.context} onChange={e => setLetterConfig({...letterConfig, context: e.target.value})} />
              <button onClick={async () => {
                const tenant = tenants.find(t => t.id === letterConfig.tenantId);
                const prop = properties.find(p => p.id === letterConfig.propertyId);
                if (!tenant) return;
                setLoading(true);
                setResult(await generateTenantLetter(tenant, prop || properties[0], letterConfig.subject, letterConfig.context));
                setLoading(false);
              }} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold">Generieren</button>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-h-[400px] flex flex-col">
        <h3 className="text-lg font-bold mb-4 border-b pb-2">Ergebnis-Vorschau</h3>

        {loading ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <i className="fa-solid fa-microchip fa-spin text-4xl mb-2 text-indigo-400"></i>
            <p className="font-bold">Analysiere Marktdaten...</p>
          </div>
        ) : activeTab === 'market' && marketAnalysis ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
                <label className="text-[10px] font-black text-emerald-600 uppercase">Ø Markt-Miete</label>
                <p className="text-2xl font-black text-emerald-700">{marketAnalysis.averageRentPerM2.toFixed(2)}€<span className="text-xs font-bold text-emerald-500">/m²</span></p>
              </div>
