interface AIToolsProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  tenants: Tenant[];
  transactions: Transaction[];
  initialPropertyId?: string;
}

interface PortalStatus {
  id: string;
  name: string;
  connected: boolean;
  lastSync?: string;
  color: string;
  icon: string;
}

const AITools: React.FC<AIToolsProps> = ({ properties, setProperties, tenants, transactions, initialPropertyId }) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');
  const [activeTab, setActiveTab] = useState<'letter' | 'expose' | 'utility' | 'portals' | 'meters' | 'market'>('letter');
  const [marketAnalysis, setMarketAnalysis] = useState<MarketData | null>(null);
  const [selectedPropertyId, setSelectedPropertyId] = useState('');

  const [portals, setPortals] = useState<PortalStatus[]>([
    { id: 'is24', name: 'ImmoScout24', connected: false, color: 'bg-orange-500', icon: 'fa-house-chimney' },
    { id: 'immonet', name: 'Immonet', connected: false, color: 'bg-blue-600', icon: 'fa-globe' },
    { id: 'immowelt', name: 'Immowelt', connected: false, color: 'bg-pink-600', icon: 'fa-door-open' }
  ]);

  const [letterConfig, setLetterConfig] = useState({
    tenantId: '',
    propertyId: '',
    subject: 'Mieterhöhung gemäß Mietspiegel',
    context: 'Die letzte Erhöhung war vor 3 Jahren. Wir müssen an den aktuellen Marktwert anpassen.'
  });

  const [utilityConfig, setUtilityConfig] = useState({
    propertyId: '',
    year: '2023'
  });

  // Meter Reading States
  const [showCamera, setShowCamera] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [extractedMeter, setExtractedMeter] = useState<{ type: MeterType; value: number; serialNumber: string; unit: string } | null>(null);
  const [meterPropertyId, setMeterPropertyId] = useState('');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (initialPropertyId) {
      setActiveTab('expose');
    }
  }, [initialPropertyId]);

  const handleMarketCheck = async () => {
    const property = properties.find(p => p.id === selectedPropertyId);
    if (!property) return alert('Bitte Objekt wählen.');
    setLoading(true);
    const data = await fetchMarketAnalysis(property);
    setMarketAnalysis(data);
    setLoading(false);
  };

  const handleSaveMeterReading = () => {
    if (!meterPropertyId || !extractedMeter) return alert('Bitte Objekt wählen und Zähler scannen.');

    const newReading: MeterReading = {
      id: Math.random().toString(36).substr(2, 9),
      type: extractedMeter.type,
      value: extractedMeter.value,
      unit: extractedMeter.unit,
      serialNumber: extractedMeter.serialNumber,
      date: new Date().toLocaleDateString('de-DE'),
      imageUrl: capturedImage || undefined
    };

    setProperties(prev => prev.map(p => 
      p.id === meterPropertyId 
        ? { ...p, meterReadings: [...(p.meterReadings || []), newReading] } 
        : p
    ));

    alert('Zählerstand erfolgreich gespeichert.');
    // Reset states
    setCapturedImage(null);
    setExtractedMeter(null);
  };

  // Camera Logic
  const startCamera = async () => {
    setShowCamera(true);
    setCapturedImage(null);
    setExtractedMeter(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera error:", err);
      alert("Kamerazugriff verweigert.");
      setShowCamera(false);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(video, 0, 0);
      const dataUrl = canvas.toDataURL('image/jpeg');
      setCapturedImage(dataUrl);
      const stream = video.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      setShowCamera(false);
      handleExtractMeter(dataUrl);
    }
  };

  const handleExtractMeter = async (img: string) => {
    setLoading(true);
    const data = await extractMeterData(img, 'image/jpeg');
    if (data) setExtractedMeter(data);
    else alert("KI konnte Zähler nicht lesen.");
    setLoading(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        <div className="flex bg-white p-1 rounded-xl shadow-sm border border-slate-100 mb-2 overflow-x-auto scrollbar-hide">
          {[
            { id: 'letter', label: 'Brief' },
            { id: 'expose', label: 'Exposé' },
            { id: 'market', label: 'Markt' },
            { id: 'utility', label: 'Abrechnung' },
            { id: 'meters', label: 'Zähler' },
            { id: 'portals', label: 'Portale' }
          ].map((tab) => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[90px] py-2 px-3 rounded-lg text-xs font-bold transition uppercase tracking-wider ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {activeTab === 'market' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 animate-in fade-in duration-300">
            <div className="flex items-center space-x-3 mb-6">
              <div className="bg-violet-100 text-violet-600 p-2 rounded-lg">
                <i className="fa-solid fa-magnifying-glass-chart text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Portal-Marktanalyse</h3>
            </div>
            <div className="space-y-4">
              <p className="text-sm text-slate-500">Analysieren Sie die aktuellen Miet- und Verkaufspreise auf Basis von Echtzeit-Daten führender Portale.</p>
              <select 
                className="w-full border p-3 rounded-xl outline-none focus:ring-2 focus:ring-violet-500 font-bold"
                value={selectedPropertyId}
                onChange={e => setSelectedPropertyId(e.target.value)}
              >
                <option value="">Objekt wählen...</option>
                {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
              <button 
                onClick={handleMarketCheck} 
                disabled={loading || !selectedPropertyId}
                className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-violet-100 hover:bg-violet-700 transition disabled:opacity-50"
              >
                {loading ? <i className="fa-solid fa-spinner fa-spin mr-2"></i> : <i className="fa-solid fa-earth-europe mr-2"></i>}
                Portaldaten abrufen
              </button>
            </div>
          </div>
        )}

        {activeTab === 'meters' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
             <div className="flex items-center space-x-3 mb-6">
              <div className="bg-cyan-100 text-cyan-600 p-2 rounded-lg">
                <i className="fa-solid fa-gauge-high text-xl"></i>
              </div>
              <h3 className="text-lg font-bold">Smart Zähler-Scanner</h3>
            </div>
            <div className="space-y-4">
               <select className="w-full border p-2.5 rounded-xl" value={meterPropertyId} onChange={e => setMeterPropertyId(e.target.value)}>
                  <option value="">Wohnobjekt wählen...</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>

                {!showCamera && !capturedImage && (
                  <div onClick={startCamera} className="border-2 border-dashed border-slate-200 rounded-3xl p-10 text-center cursor-pointer hover:border-cyan-400 hover:bg-cyan-50 transition">
                    <i className="fa-solid fa-camera text-2xl text-cyan-600 mb-2"></i>
                    <p className="font-bold">Zähler scannen</p>
                    <p className="text-[10px] text-slate-400 mt-1 uppercase font-black">Unterstützt Strom, Gas & Wasser</p>
                  </div>
                )}

                {showCamera && (
                   <div className="relative rounded-3xl overflow-hidden bg-black aspect-[3/4]">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <div className="absolute inset-0 border-2 border-cyan-400/30 m-12 rounded-2xl pointer-events-none"></div>
                      <button onClick={capturePhoto} className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-slate-900 w-16 h-16 rounded-full border-4 border-cyan-400 flex items-center justify-center shadow-2xl">
                        <div className="w-12 h-12 bg-white rounded-full border border-slate-200"></div>
                      </button>
                   </div>
                )}

                <canvas ref={canvasRef} className="hidden" />

                {capturedImage && (
                  <div className="space-y-4 animate-in fade-in">
                    <div className="relative">
                      <img src={capturedImage} className="w-full h-48 object-cover rounded-2xl border border-slate-200" />
                      <button onClick={() => {setCapturedImage(null); setExtractedMeter(null);}} className="absolute top-2 right-2 bg-black/50 text-white w-8 h-8 rounded-full">
                        <i className="fa-solid fa-xmark"></i>
                      </button>
                    </div>

                    {extractedMeter && (
                      <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100">
                        <div className="grid grid-cols-2 gap-4 mb-5">
                           <div>
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Typ</label>
                             <p className="font-bold text-slate-800">{extractedMeter.type}</p>
                           </div>
                           <div>
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Einheit</label>
                             <p className="font-bold text-slate-800">{extractedMeter.unit}</p>
                           </div>
                           <div className="col-span-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Aktueller Stand</label>
                             <p className="font-black text-3xl text-indigo-600">{extractedMeter.value.toLocaleString('de-DE')} {extractedMeter.unit}</p>
                           </div>
                           <div className="col-span-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Zählernummer</label>
                             <p className="font-mono font-bold text-slate-600">{extractedMeter.serialNumber}</p>
                           </div>
                        </div>
                        <button 
                          onClick={handleSaveMeterReading}
                          disabled={!meterPropertyId}
                          className="w-full bg-cyan-600 text-white py-3.5 rounded-xl font-black shadow-lg shadow-cyan-100 hover:bg-cyan-700 transition disabled:opacity-50"
                        >
                          Zählerstand speichern
                        </button>
                      </div>
                    )}
                  </div>
                )}
            </div>
          </div>
        )}

        {/* Other Tabs remain the same but omitted for brevity if no changes needed */}
        {activeTab === 'letter' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Mieter-Anschreiben</h3>
            <div className="space-y-4">
              <select className="w-full border p-2 rounded-xl" value={letterConfig.tenantId} onChange={e => setLetterConfig({...letterConfig, tenantId: e.target.value})}>
                <option value="">Mieter...</option>
                {tenants.map(t => <option key={t.id} value={t.id}>{t.firstName} {t.lastName}</option>)}
              </select>
              <textarea className="w-full border p-2 rounded-xl h-24" placeholder="Kontext..." value={letterConfig.context} onChange={e => setLetterConfig({...letterConfig, context: e.target.value})} />
              <button onClick={async () => {
                const tenant = tenants.find(t => t.id === letterConfig.tenantId);
                const prop = properties.find(p => p.id === letterConfig.propertyId);
                if (!tenant) return;
                setLoading(true);
                setResult(await generateTenantLetter(tenant, prop || properties[0], letterConfig.subject, letterConfig.context));
                setLoading(false);
              }} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold">Generieren</button>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 min-h-[400px] flex flex-col">
        <h3 className="text-lg font-bold mb-4 border-b pb-2">Vorschau & Historie</h3>

        {loading ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <i className="fa-solid fa-microchip fa-spin text-4xl mb-2 text-indigo-400"></i>
            <p className="font-bold">KI verarbeitet Daten...</p>
          </div>
        ) : activeTab === 'meters' && meterPropertyId ? (
          <div className="flex-1 overflow-y-auto">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Gespeicherte Zählerstände</h4>
            <div className="space-y-3">
              {properties.find(p => p.id === meterPropertyId)?.meterReadings?.slice().reverse().map(reading => (
                <div key={reading.id} className="p-3 bg-slate-50 border border-slate-100 rounded-xl flex justify-between items-center">
                  <div className="flex items-center space-x-3">
                    <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-indigo-500 border border-slate-100">
                      <i className={`fa-solid ${reading.type === 'Strom' ? 'fa-bolt' : reading.type === 'Gas' ? 'fa-fire' : 'fa-droplet'}`}></i>
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-800">{reading.value} {reading.unit}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase">{reading.date} • {reading.serialNumber}</p>
                    </div>
                  </div>
                  {reading.imageUrl && (
                    <div className="w-10 h-10 rounded-lg overflow-hidden border border-slate-200 shrink-0">
                      <img src={reading.imageUrl} className="w-full h-full object-cover" />
                    </div>
                  )}
                </div>
              ))}
              {(!properties.find(p => p.id === meterPropertyId)?.meterReadings || properties.find(p => p.id === meterPropertyId)?.meterReadings?.length === 0) && (
                <div className="text-center py-12 opacity-20">
                  <i className="fa-solid fa-list-check text-4xl mb-2"></i>
                  <p className="text-xs font-bold">Keine Historie vorhanden</p>
                </div>
              )}
            </div>
          </div>
        ) : result ? (
          <div className="flex-1 overflow-y-auto whitespace-pre-wrap text-sm leading-relaxed p-4 bg-slate-50 rounded-xl border">{result}</div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-300 italic">
            <i className="fa-solid fa-robot text-4xl mb-4 opacity-20"></i>
            <p>Wählen Sie ein Objekt aus der Liste.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AITools;

