                    <div className="relative group">
                      <img src={capturedImage} className="w-full h-64 object-cover rounded-2xl border-2 border-slate-200 shadow-lg" />

                      {loading && (
                        <div className="absolute inset-0 bg-black/40 backdrop-blur-sm rounded-2xl flex flex-col items-center justify-center text-white">
                          <div className="w-full max-w-[80%] h-1 bg-cyan-400/30 rounded-full overflow-hidden relative mb-4">
                            <div className="absolute inset-0 bg-cyan-400 animate-[scan_2s_ease-in-out_infinite]"></div>
                          </div>
                          <p className="font-black text-xs uppercase tracking-widest">KI analysiert Bild...</p>
                        </div>
                      )}

                      {!loading && (
                        <button onClick={() => {setCapturedImage(null); setExtractedMeter(null);}} className="absolute top-4 right-4 bg-white/90 text-slate-900 w-10 h-10 rounded-full shadow-lg hover:bg-white transition">
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      )}
                    </div>

                    {extractedMeter && !loading && (
                      <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 shadow-inner">
                        <div className="grid grid-cols-2 gap-4 mb-5">
                           <div>
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Zählertyp</label>
                             <div className="flex items-center space-x-2">
                               <i className={`fa-solid ${extractedMeter.type === 'Strom' ? 'fa-bolt text-yellow-500' : extractedMeter.type === 'Gas' ? 'fa-fire text-orange-500' : 'fa-droplet text-blue-500'}`}></i>
                               <p className="font-bold text-slate-800">{extractedMeter.type}</p>
                             </div>
                           </div>
                           <div>
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Einheit</label>
                             <p className="font-bold text-slate-800">{extractedMeter.unit}</p>
                           </div>
                           <div className="col-span-2 bg-white p-4 rounded-xl border border-slate-200">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Gelesener Stand</label>
                             <div className="flex items-baseline space-x-2">
                               <p className="font-black text-4xl text-indigo-600 tracking-tighter">{extractedMeter.value.toLocaleString('de-DE')}</p>
                               <span className="text-xl font-bold text-slate-400">{extractedMeter.unit}</span>
                             </div>
                           </div>
                           <div className="col-span-2">
                             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Zählernummer</label>
                             <p className="font-mono font-bold text-slate-600 bg-slate-200 px-2 py-1 rounded inline-block">{extractedMeter.serialNumber || 'Nicht erkannt'}</p>
                           </div>
                        </div>
                        <button 
                          onClick={handleSaveMeterReading}
                          disabled={!meterPropertyId}
                          className="w-full bg-cyan-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-cyan-100 hover:bg-cyan-700 transition active:scale-[0.98] disabled:opacity-50"
                        >
                          <i className="fa-solid fa-cloud-arrow-up mr-2"></i> In Historie speichern
                        </button>
                      </div>
                    )}
                  </div>
                )}
            </div>
          </div>
        )}

        {/* Other Tabs */}
        {activeTab === 'letter' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-6">Mieter-Anschreiben</h3>
            <div className="space-y-4">
              <select className="w-full border p-2 rounded-xl" value={letterConfig.tenantId} onChange={e => setLetterConfig({...letterConfig, tenantId: e.target.value})}>
                <option value="">Mieter...</option>
                {tenants.map(t => <option key={t.id} value={t.id}>{t.firstName} {t.lastName}</option>)}
              </select>
              <textarea className="w-full border p-2 rounded-xl h-24" placeholder="Kontext..." value={letterConfig.context} onChange={e => setLetterConfig({...letterConfig, context: e.target.value})} />
              <button onClick={async () => {
                const tenant = tenants.find(t => t.id === letterConfig.tenantId);
                const prop = properties.find(p => p.id === letterConfig.propertyId);
                if (!tenant) return;
                setLoading(true);
                setResult(await generateTenantLetter(tenant, prop || properties[0], letterConfig.subject, letterConfig.context));
                setLoading(false);
              }} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold">Generieren</button>
            </div>
          </div>
