          <div className="flex-1 overflow-y-auto">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Gespeicherte Zählerstände</h4>
            <div className="space-y-3">
              {properties.find(p => p.id === meterPropertyId)?.meterReadings?.slice().reverse().map(reading => (
                <div key={reading.id} className="p-3 bg-slate-50 border border-slate-100 rounded-xl flex justify-between items-center hover:bg-white hover:shadow-sm transition">
                  <div className="flex items-center space-x-3">
