                      reading.type === 'Strom' ? 'bg-yellow-50 text-yellow-600' : reading.type === 'Gas' ? 'bg-orange-50 text-orange-600' : 'bg-blue-50 text-blue-600'
                    }`}>
                      <i className={`fa-solid ${reading.type === 'Strom' ? 'fa-bolt' : reading.type === 'Gas' ? 'fa-fire' : 'fa-droplet'}`}></i>
                    </div>
                    <div>
                      <p className="text-sm font-black text-slate-800">{reading.value.toLocaleString('de-DE')} {reading.unit}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-wider">{reading.date} • SN: {reading.serialNumber || 'N/A'}</p>
                    </div>
                  </div>
                  {reading.imageUrl && (
                    <div className="w-12 h-12 rounded-lg overflow-hidden border-2 border-white shadow-sm shrink-0">
                      <img src={reading.imageUrl} className="w-full h-full object-cover" />
                    </div>
                  )}
