            serialNumber: { type: Type.STRING },
            unit: { type: Type.STRING }
          },
          required: ['type', 'value', 'unit']
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Meter Extraction Error:", error);
    return null;
