                    <div className="w-16 h-16 bg-cyan-100 text-cyan-600 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                      <i className="fa-solid fa-camera text-2xl"></i>
                    </div>
                    <p className="font-bold text-slate-700">Kamera starten</p>
                    <p className="text-[10px] text-slate-400 mt-2 uppercase font-black tracking-widest">Strom, Gas & Wasser-Analyse</p>
                  </div>
