                {showCamera && (
                   <div className="relative rounded-3xl overflow-hidden bg-black aspect-[3/4] shadow-2xl border-4 border-slate-900 animate-in zoom-in-95 duration-300">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                        <div className="w-4/5 h-1/3 border-2 border-cyan-400 rounded-2xl shadow-[0_0_0_100vw_rgba(0,0,0,0.5)]"></div>
                      </div>
                      <div className="absolute bottom-0 left-0 right-0 p-6 flex justify-between items-center">
                        <button onClick={stopCamera} className="w-12 h-12 bg-white/20 backdrop-blur-md text-white rounded-full flex items-center justify-center"><i className="fa-solid fa-xmark"></i></button>
                        <button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-cyan-400 p-1"><div className="w-full h-full bg-white rounded-full border-2 border-slate-200"></div></button>
