import React, { useState } from 'react';
import { Property, Transaction, Loan, TransactionType } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, Legend } from 'recharts';
import { generateInvestmentStrategy } from '../services/geminiService';

interface InvestorDashboardProps {
  properties: Property[];
  transactions: Transaction[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
}

const InvestorDashboard: React.FC<InvestorDashboardProps> = ({ properties, transactions, setProperties }) => {
  const [selectedPropertyId, setSelectedPropertyId] = useState<string>(properties[0]?.id || '');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  const selectedProperty = properties.find(p => p.id === selectedPropertyId);

  // Financial Calculations
  const calcMetrics = (prop: Property) => {
    const annualRent = prop.units.reduce((sum, u) => sum + (u.baseRent * 12), 0);
    const price = prop.purchasePrice || 0;
    const grossYield = price > 0 ? (annualRent / price) * 100 : 0;

    const propTransactions = transactions.filter(t => t.propertyId === prop.id);
    const annualExpenses = propTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    const monthlyLoanService = prop.loans?.reduce((sum, l) => sum + l.monthlyInstallment, 0) || 0;
    const annualLoanService = monthlyLoanService * 12;

    const cashflow = (annualRent - annualExpenses - annualLoanService) / 12;
    const netYield = price > 0 ? ((annualRent - annualExpenses) / price) * 100 : 0;

    return { grossYield, netYield, cashflow, annualRent, annualExpenses, annualLoanService };
  };

  const metrics = selectedProperty ? calcMetrics(selectedProperty) : null;

  const handleAiAnalysis = async () => {
    if (!selectedProperty || !metrics) return;
    setIsAnalyzing(true);
    const analysis = await generateInvestmentStrategy(selectedProperty, metrics);
    setAiAnalysis(analysis);
    setIsAnalyzing(false);
  };

  const pieData = metrics ? [
    { name: 'Instandhaltung/Kosten', value: metrics.annualExpenses },
    { name: 'Darlehensschuld', value: metrics.annualLoanService },
    { name: 'Reingewinn', value: Math.max(0, metrics.annualRent - metrics.annualExpenses - metrics.annualLoanService) }
  ] : [];

  const COLORS = ['#94a3b8', '#6366f1', '#10b981'];

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-xl font-bold text-slate-800">Portfolio & Rendite Analyse</h2>
          <p className="text-sm text-slate-500">Überwachen Sie Cashflow, Darlehen und Performance Ihrer Assets.</p>
        </div>
        <select 
          className="bg-slate-50 border border-slate-200 p-2.5 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm"
          value={selectedPropertyId}
          onChange={e => { setSelectedPropertyId(e.target.value); setAiAnalysis(null); }}
        >
          {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
      </div>

      {!selectedProperty && (
        <div className="py-20 text-center text-slate-400 italic">Bitte legen Sie zuerst ein Objekt an.</div>
      )}

      {selectedProperty && metrics && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Performance Stats */}
          <div className="lg:col-span-2 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <StatCard title="Bruttorendite" value={`${metrics.grossYield.toFixed(2)}%`} icon="fa-chart-line" color="text-indigo-600" />
              <StatCard title="Nettorendite" value={`${metrics.netYield.toFixed(2)}%`} icon="fa-chart-area" color="text-emerald-600" />
              <StatCard title="Cashflow/Monat" value={`${metrics.cashflow.toFixed(2)}€`} icon="fa-money-bill-trend-up" color={metrics.cashflow >= 0 ? 'text-emerald-600' : 'text-red-600'} />
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <h3 className="font-bold text-slate-800 mb-6">Miet- & Kostenstruktur (Jährlich)</h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={pieData} innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                      {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                    </Pie>
                    <Tooltip />
                    <Legend />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-slate-800">Finanzierung & Darlehen</h3>
                <button className="text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-lg">Darlehen hinzufügen</button>
              </div>
              <div className="space-y-4">
                {selectedProperty.loans && selectedProperty.loans.length > 0 ? (
                  selectedProperty.loans.map(loan => (
                    <div key={loan.id} className="p-4 border border-slate-100 rounded-xl bg-slate-50 flex flex-col md:flex-row justify-between gap-4">
                      <div>
                        <p className="text-sm font-bold text-slate-800">{loan.bankName}</p>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Zinsbindung bis: {loan.fixedUntil}</p>
