            <i className="fa-solid fa-robot text-5xl mb-6 opacity-20"></i>
            <p className="font-bold text-slate-400 uppercase tracking-widest text-[10px]">Warten auf Eingabe</p>
          </div>
        )}
      </div>
    </div>
  );
};

